    public DaoAuthenticationProvider authenticationProvider() {
        DaoAuthenticationProvider provider = new DaoAuthenticationProvider();
        provider.setUserDetailsService(rbacUserDetailsService);
        provider.setPasswordEncoder(passwordEncoder());
        return provider;
    }

    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception {
        return config.getAuthenticationManager();
    }

    // ── Filter Chain ─────────────────────────────────────────────────────────

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authenticationProvider(authenticationProvider())

            // CSRF disabled (REST API + session cookie)
            .csrf(csrf -> csrf.disable())

            // ── Authorization rules ──────────────────────────────────────────
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/auth/**").permitAll()
                .requestMatchers(HttpMethod.GET,  "/api/forms/{id}").permitAll()
                .requestMatchers(HttpMethod.GET,  "/api/forms/{id}/render").permitAll()
                .requestMatchers(HttpMethod.POST, "/api/forms/{id}/submit").permitAll()
                .requestMatchers("/api/forms/**").authenticated()
                .requestMatchers("/api/shared-options/**").authenticated()
                .requestMatchers("/api/roles/**").authenticated()
                .requestMatchers("/api/users/**").authenticated()
                .requestMatchers("/api/logs/**").authenticated()
                .requestMatchers("/v3/api-docs/**", "/swagger-ui/**", "/swagger-ui.html").permitAll()
                .anyRequest().permitAll()
            )

            // ── Form-based login ─────────────────────────────────────────────
            .formLogin(form -> form
                .loginProcessingUrl("/api/auth/login")
                .successHandler((req, res, auth) -> {
                    // ── Build response with RBAC data ──
                    Map<String, Object> response = new LinkedHashMap<>();
                    response.put("username", auth.getName());
                    response.put("authorities", auth.getAuthorities().stream()
                            .map(a -> a.getAuthority()).toList());

                    try {
                        List<Map<String, Object>> rows = jdbc.queryForList(
                                "SELECT id, username, name, email FROM rbac_users WHERE username = ?",
                                auth.getName());
                        if (!rows.isEmpty()) {
                            Map<String, Object> rbacUser = rows.get(0);
                            Integer userId = (Integer) rbacUser.get("id");

                            // Store in session for PermissionInterceptor
                            HttpSession session = req.getSession(true);
                            session.setAttribute("USER_ID", userId);
                            log.debug("Stored USER_ID={} in session for '{}'", userId, auth.getName());

                            response.put("userId", userId);
                            response.put("name", rbacUser.get("name"));
                            response.put("email", rbacUser.get("email"));

                            // Fetch roles
                            List<Map<String, Object>> roleRows = jdbc.queryForList(
                                    "SELECT r.id, r.role_name, r.is_system_role " +
                                    "FROM user_roles ur JOIN roles r ON r.id = ur.role_id " +
                                    "WHERE ur.user_id = ? ORDER BY r.role_name",
                                    userId);
                            response.put("roles", roleRows.stream().map(row -> {
                                Map<String, Object> role = new LinkedHashMap<>();
                                role.put("id", row.get("id"));
                                role.put("roleName", row.get("role_name"));
                                role.put("isSystemRole", row.get("is_system_role"));
                                return role;
                            }).toList());

                            // Fetch effective permissions
                            List<String> perms = jdbc.queryForList(
                                    "SELECT DISTINCT p.permission_key " +
                                    "FROM user_roles ur " +
                                    "JOIN role_permissions rp ON rp.role_id = ur.role_id " +
                                    "JOIN permissions p ON p.id = rp.permission_id " +
                                    "WHERE ur.user_id = ? ORDER BY p.permission_key",
                                    String.class, userId);
                            response.put("permissions", perms);
                        } else {
                            log.warn("No RBAC profile found for '{}' after successful auth", auth.getName());
                            response.put("roles", List.of());
                            response.put("permissions", List.of());
                        }
                    } catch (Exception e) {
                        log.warn("Could not resolve RBAC profile for '{}': {}", auth.getName(), e.getMessage());
                        response.put("roles", List.of());
                        response.put("permissions", List.of());
                    }

                    res.setStatus(HttpStatus.OK.value());
                    res.setContentType("application/json");
                    res.getWriter().write(mapper.writeValueAsString(response));
                })
                .failureHandler((req, res, ex) -> {
                    res.setStatus(HttpStatus.UNAUTHORIZED.value());
                    res.setContentType("application/json");
                    res.getWriter().write(mapper.writeValueAsString(
                        Map.of("error", "Invalid username or password")
                    ));
                })
                .permitAll()
            )

            // ── Logout ───────────────────────────────────────────────────────
            .logout(logout -> logout
                .logoutUrl("/api/auth/logout")
                .invalidateHttpSession(true)
                .deleteCookies("JSESSIONID")
                .clearAuthentication(true)
                .logoutSuccessHandler((req, res, auth) -> {
                    res.setStatus(HttpStatus.OK.value());
                    res.setContentType("application/json");
                    res.getWriter().write("{\"message\":\"Logged out successfully\"}");
                })
                .permitAll()
            )

            // ── 401 JSON for unauthenticated API calls ───────────────────────
            .exceptionHandling(ex -> ex
                .authenticationEntryPoint((req, res, authEx) -> {
                    res.setStatus(HttpStatus.UNAUTHORIZED.value());
                    res.setContentType("application/json");
                    res.getWriter().write("{\"error\":\"Authentication required\"}");
                })
            )

            // ── Session management ───────────────────────────────────────────
            .sessionManagement(session -> session
                .maximumSessions(10)
            );

        return http.build();
    }
}

package com.formbuilder.controller;

import com.formbuilder.rbac.service.UserRoleService;
import com.formbuilder.service.AuditLogService;
import lombok.RequiredArgsConstructor;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.time.LocalDate;
import java.util.List;
import java.util.Map;
import java.util.Set;

@RestController
@RequestMapping("/api/logs")
@RequiredArgsConstructor
public class AuditLogController {

    private final AuditLogService auditLogService;
    private final UserRoleService userRoleService;

    @GetMapping("/admin")
    public ResponseEntity<?> getAdminLogs(
            Authentication auth,
            @RequestParam(required = false) String action,
            @RequestParam(required = false) String user,
            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate fromDate,
            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate toDate) {

        Set<String> roleNames = userRoleService.getUserRoleNames(auth.getName());
        if (!roleNames.contains("Admin")) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("error", "Only Admin can access full audit logs."));
        }

        List<Map<String, Object>> logs = auditLogService.getAdminLogs(action, user, fromDate, toDate);
        return ResponseEntity.ok(logs);
    }

    @GetMapping("/role-assignments")
    public ResponseEntity<?> getRoleAssignmentLogs(
            Authentication auth,
            @RequestParam(required = false) Integer roleId,
            @RequestParam(required = false) String user,
            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate fromDate,
            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate toDate) {

        Set<String> roleNames = userRoleService.getUserRoleNames(auth.getName());
        boolean isAdmin = roleNames.contains("Admin");
        boolean isRoleAdmin = roleNames.contains("Role Administrator");

        if (!isAdmin && !isRoleAdmin) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("error", "Only Admin or Role Administrator can access role assignment logs."));
        }

        List<Map<String, Object>> logs = auditLogService.getRoleAssignmentLogs(roleId, user, fromDate, toDate);
        return ResponseEntity.ok(logs);
    }
}

package com.formbuilder.controller;

import com.formbuilder.dto.FormDTO;
import com.formbuilder.entity.FormEntity;
import com.formbuilder.entity.FormGroupEntity;
import com.formbuilder.entity.StaticFormFieldEntity;
import com.formbuilder.rbac.service.UserRoleService;
import com.formbuilder.service.FormRenderService;
import com.formbuilder.service.FormService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.*;
import java.util.stream.Collectors;

/**
 * REST Controller for Form CRUD operations.
 * Now uses role-based form visibility via UserRoleService.
 */
@RestController
@RequestMapping("/api/forms")
@RequiredArgsConstructor
public class FormController {

    private final FormService formService;
    private final FormRenderService formRenderService;
    private final UserRoleService userRoleService;

    /** List only the forms that belong to the authenticated user. */
    @GetMapping
    public ResponseEntity<List<Map<String, Object>>> getAll(Authentication auth) {
        String username = auth.getName();
        Set<String> roleNames = userRoleService.getUserRoleNames(username);

        List<FormEntity> forms = formService.getFormsForRole(username, roleNames);

        // Annotate each form with ownership flag and effective permissions
        List<Map<String, Object>> response = forms.stream().map(form -> {
            Map<String, Object> map = new LinkedHashMap<>();
            map.put("id", form.getId());
            map.put("name", form.getName());
            map.put("description", form.getDescription());
            map.put("tableName", form.getTableName());
            map.put("status", form.getStatus());
            map.put("visibility", form.getVisibility());
            map.put("allowedRoles", form.getAllowedRoles());
            map.put("createdBy", form.getCreatedBy());
            map.put("createdAt", form.getCreatedAt());
            map.put("updatedAt", form.getUpdatedAt());
            map.put("allowMultipleSubmissions", form.isAllowMultipleSubmissions());
            map.put("showTimestamp", form.isShowTimestamp());
            map.put("expiresAt", form.getExpiresAt());
            map.put("fields", form.getFields());

            // Ownership flag — frontend uses this to show/hide edit/delete buttons
            boolean isOwner = username.equals(form.getCreatedBy());
            map.put("isOwner", isOwner);

            // Effective actions: what can this user do with this form?
            boolean isAdmin = roleNames.contains(ROLE_ADMIN);
            boolean isRoleAdmin = roleNames.contains(ROLE_ROLE_ADMIN);
            boolean isAdmin = roleNames.contains("Admin");
            map.put("canDelete", !isRoleAdmin && (isOwner || isAdmin));
            map.put("canEdit", isOwner || isAdmin);
            map.put("canDelete", isOwner || isAdmin);
            map.put("canPublish", isOwner || isAdmin);

        return ResponseEntity.ok(response);
    }

    /** Single form with static fields bundled — used by builder edit page. */
    @GetMapping("/{id}")
    public ResponseEntity<Map<String, Object>> getById(@PathVariable UUID id) {
        FormEntity form = formService.getFormById(id);
        List<StaticFormFieldEntity> statics = formService.getStaticFields(id);

        // Convert statics to simple maps for JSON response
        List<Map<String, Object>> staticList = new ArrayList<>();
        for (StaticFormFieldEntity sf : statics) {
            Map<String, Object> m = new LinkedHashMap<>();
            m.put("id", sf.getId());
            m.put("fieldType", sf.getFieldType());
            m.put("data", sf.getData());
            m.put("fieldOrder", sf.getFieldOrder());
            m.put("isStatic", true);
            staticList.add(m);
        }

        Map<String, Object> response = new LinkedHashMap<>();
        response.put("id", form.getId());
        response.put("name", form.getName());
        response.put("description", form.getDescription());
        response.put("tableName", form.getTableName());
        response.put("status", form.getStatus());
        response.put("visibility", form.getVisibility());
        response.put("allowedRoles", form.getAllowedRoles());
        response.put("createdBy", form.getCreatedBy());
        response.put("createdAt", form.getCreatedAt());
        response.put("updatedAt", form.getUpdatedAt());
        response.put("allowMultipleSubmissions", form.isAllowMultipleSubmissions());
        response.put("showTimestamp", form.isShowTimestamp());
        response.put("expiresAt", form.getExpiresAt());
        response.put("fields", form.getFields());
        response.put("staticFields", staticList);

        // Groups
        List<FormGroupEntity> groups = formService.getGroups(id);
        List<Map<String, Object>> groupList = new ArrayList<>();
        for (FormGroupEntity g : groups) {
            Map<String, Object> gm = new LinkedHashMap<>();
            gm.put("id", g.getId());
            gm.put("groupTitle", g.getGroupTitle());
            gm.put("groupDescription", g.getGroupDescription());
            gm.put("groupOrder", g.getGroupOrder());
            gm.put("rulesJson", g.getRulesJson());
            groupList.add(gm);
        }
        response.put("groups", groupList);

        return ResponseEntity.ok(response);
    }

    /**
     * Public render — returns 403 if DRAFT.
     * No ownership check: anyone with the link can submit to a published form.
     */
    @GetMapping("/{id}/render")
    public ResponseEntity<?> render(@PathVariable UUID id, jakarta.servlet.http.HttpSession session) {
        FormEntity form = formService.getFormById(id);
        if (form.getStatus() == FormEntity.FormStatus.DRAFT) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("error", "This form is not published yet.", "status", "DRAFT"));
        }

        if (!form.isAllowMultipleSubmissions()) {
            String sessionKey = "submitted_" + id;
            if (session.getAttribute(sessionKey) != null) {
                return ResponseEntity.status(HttpStatus.CONFLICT)
                        .body(Map.of("error", "You have already submitted this form.", "status", "CONFLICT"));
            }
        }

        return ResponseEntity.ok(formRenderService.render(id));
    }

    /**
     * Admin/Role Administrator render — always returns active form for preview.
     * Admin and Role Administrator can preview any non-deleted form;
     * other users can preview only forms they can act on.
     */
    @GetMapping("/{id}/render/admin")
     * Admin render — always returns form (for builder preview).
     * Admin can preview any form; others can only preview their own.
        boolean isRoleAdmin = roles.contains(ROLE_ROLE_ADMIN);

        if (isAdmin || isRoleAdmin) {
            // Non-deleted only (findByIdWithFields)
            formService.getFormById(id);
        } else {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        formService.getFormForAction(id, auth.getName(), isAdmin);
    }

    /** Update — owner or Admin can edit a form. */
    @PutMapping("/{id}")
    public ResponseEntity<FormEntity> update(
            @PathVariable UUID id,
            @RequestBody FormDTO dto,
            Authentication auth) {
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        return ResponseEntity.ok(formService.updateForm(id, dto, auth.getName(), isAdmin));
    }

    /** Soft-delete — moves form to trash. Owner or Admin. */
    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable UUID id, Authentication auth) {
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
    }

    /** List trash — Admin sees all, others see their own. */
    @GetMapping("/trash")
    public ResponseEntity<List<FormEntity>> getTrash(Authentication auth) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        return ResponseEntity.ok(formService.getTrashForms(auth.getName(), isAdmin));
    }

    /** Restore — move a trashed form back to active. Owner or Admin. */
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        return ResponseEntity.ok(Map.of(
                "id", id.toString(),
                "message", "Form restored successfully",
                "name", form.getName()));
    }

    /** Permanently delete — only works if form is already in trash. Owner or Admin. */
    @DeleteMapping("/{id}/permanent")
    public ResponseEntity<Void> permanentDelete(@PathVariable UUID id, Authentication auth) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        formService.permanentDeleteForm(id, auth.getName(), isAdmin);
        return ResponseEntity.noContent().build();
    }

    /** Publish — owner or Admin can publish a form. */
    @PatchMapping("/{id}/publish")
    public ResponseEntity<Map<String, Object>> publish(@PathVariable UUID id, Authentication auth) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        formService.publishForm(id, auth.getName(), isAdmin);
        return ResponseEntity.ok(Map.of(
                "id", id.toString(),
                "status", "PUBLISHED",
                "message", "Form published successfully"));
    }

    /** Unpublish — owner or Admin can unpublish a form. */
    @PatchMapping("/{id}/unpublish")
    public ResponseEntity<Map<String, Object>> unpublish(@PathVariable UUID id, Authentication auth) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        formService.unpublishForm(id, auth.getName(), isAdmin);
        return ResponseEntity.ok(Map.of(
                "id", id.toString(),
                "status", "DRAFT",
                "message", "Form unpublished successfully"));
    }
}

package com.formbuilder.controller;

import com.formbuilder.dto.FormDTO;
import com.formbuilder.entity.FormEntity;
import com.formbuilder.entity.FormGroupEntity;
import com.formbuilder.entity.StaticFormFieldEntity;
import com.formbuilder.rbac.service.UserRoleService;
import com.formbuilder.service.AuditLogService;
import com.formbuilder.service.FormRenderService;
import com.formbuilder.service.FormService;
import jakarta.servlet.http.HttpSession;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.*;
import java.util.stream.Collectors;

/**
 * REST Controller for Form CRUD operations.
 * Now uses role-based form visibility via UserRoleService.
 */
@RestController
@RequestMapping("/api/forms")
@RequiredArgsConstructor
public class FormController {

    private final FormService formService;
    private final FormRenderService formRenderService;
    private final UserRoleService userRoleService;
    private final AuditLogService auditLogService;

    private static final String ROLE_ADMIN = "Admin";
    private static final String ROLE_ROLE_ADMIN = "Role Administrator";

    /** List only the forms that belong to the authenticated user. */
    @GetMapping
    public ResponseEntity<List<Map<String, Object>>> getAll(Authentication auth) {
        String username = auth.getName();
        Set<String> roleNames = userRoleService.getUserRoleNames(username);

        List<FormEntity> forms = formService.getFormsForRole(username, roleNames);

        // Annotate each form with ownership flag and effective permissions
        List<Map<String, Object>> response = forms.stream().map(form -> {
            Map<String, Object> map = new LinkedHashMap<>();
            map.put("id", form.getId());
            map.put("name", form.getName());
            map.put("description", form.getDescription());
            map.put("tableName", form.getTableName());
            map.put("status", form.getStatus());
            map.put("visibility", form.getVisibility());
            map.put("allowedRoles", form.getAllowedRoles());
            map.put("createdBy", form.getCreatedBy());
            map.put("createdAt", form.getCreatedAt());
            map.put("updatedAt", form.getUpdatedAt());
            map.put("allowMultipleSubmissions", form.isAllowMultipleSubmissions());
            map.put("showTimestamp", form.isShowTimestamp());
            map.put("expiresAt", form.getExpiresAt());
            map.put("fields", form.getFields());

            // Ownership flag — frontend uses this to show/hide edit/delete buttons
            boolean isOwner = username.equals(form.getCreatedBy());
            map.put("isOwner", isOwner);

            // Effective actions: what can this user do with this form?
            boolean isAdmin = roleNames.contains(ROLE_ADMIN);
            boolean isRoleAdmin = roleNames.contains(ROLE_ROLE_ADMIN);
            boolean isBuilder = roleNames.contains("Builder");
            map.put("canEdit", !isRoleAdmin && (isOwner || isAdmin));
            map.put("canDelete", !isRoleAdmin && (isOwner || isAdmin));
            map.put("canPublish", !isRoleAdmin && (isOwner || isAdmin));
            map.put("canViewSubmissions", isOwner || isAdmin || isBuilder || roleNames.contains("Manager"));

            return map;
        }).collect(Collectors.toList());

        return ResponseEntity.ok(response);
    }

    /** Single form with static fields bundled — used by builder edit page. */
    @GetMapping("/{id}")
    public ResponseEntity<Map<String, Object>> getById(@PathVariable UUID id) {
        FormEntity form = formService.getFormById(id);
        List<StaticFormFieldEntity> statics = formService.getStaticFields(id);

        // Convert statics to simple maps for JSON response
        List<Map<String, Object>> staticList = new ArrayList<>();
        for (StaticFormFieldEntity sf : statics) {
            Map<String, Object> m = new LinkedHashMap<>();
            m.put("id", sf.getId());
            m.put("fieldType", sf.getFieldType());
            m.put("data", sf.getData());
            m.put("fieldOrder", sf.getFieldOrder());
            m.put("isStatic", true);
            staticList.add(m);
        }

        Map<String, Object> response = new LinkedHashMap<>();
        response.put("id", form.getId());
        response.put("name", form.getName());
        response.put("description", form.getDescription());
        response.put("tableName", form.getTableName());
        response.put("status", form.getStatus());
        response.put("visibility", form.getVisibility());
        response.put("allowedRoles", form.getAllowedRoles());
        response.put("createdBy", form.getCreatedBy());
        response.put("createdAt", form.getCreatedAt());
        response.put("updatedAt", form.getUpdatedAt());
        response.put("allowMultipleSubmissions", form.isAllowMultipleSubmissions());
        response.put("showTimestamp", form.isShowTimestamp());
        response.put("expiresAt", form.getExpiresAt());
        response.put("fields", form.getFields());
        response.put("staticFields", staticList);

        // Groups
        List<FormGroupEntity> groups = formService.getGroups(id);
        List<Map<String, Object>> groupList = new ArrayList<>();
        for (FormGroupEntity g : groups) {
            Map<String, Object> gm = new LinkedHashMap<>();
            gm.put("id", g.getId());
            gm.put("groupTitle", g.getGroupTitle());
            gm.put("groupDescription", g.getGroupDescription());
            gm.put("groupOrder", g.getGroupOrder());
            gm.put("rulesJson", g.getRulesJson());
            groupList.add(gm);
        }
        response.put("groups", groupList);

        return ResponseEntity.ok(response);
    }

    /**
     * Public render — returns 403 if DRAFT.
     * No ownership check: anyone with the link can submit to a published form.
     */
    @GetMapping("/{id}/render")
    public ResponseEntity<?> render(@PathVariable UUID id, jakarta.servlet.http.HttpSession session) {
        FormEntity form = formService.getFormById(id);
        if (form.getStatus() == FormEntity.FormStatus.DRAFT) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("error", "This form is not published yet.", "status", "DRAFT"));
        }

        if (!form.isAllowMultipleSubmissions()) {
            String sessionKey = "submitted_" + id;
            if (session.getAttribute(sessionKey) != null) {
                return ResponseEntity.status(HttpStatus.CONFLICT)
                        .body(Map.of("error", "You have already submitted this form.", "status", "CONFLICT"));
            }
        }

        return ResponseEntity.ok(formRenderService.render(id));
    }

    /**
     * Admin/Role Administrator render — always returns active form for preview.
     * Admin and Role Administrator can preview any non-deleted form;
     * other users can preview only forms they can act on.
     */
    @GetMapping("/{id}/render/admin")
    public ResponseEntity<?> renderAdmin(@PathVariable UUID id, Authentication auth) {
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        boolean isRoleAdmin = roles.contains(ROLE_ROLE_ADMIN);

        if (isAdmin || isRoleAdmin) {
            // Non-deleted only (findByIdWithFields)
            formService.getFormById(id);
        } else {
            formService.getFormForAction(id, auth.getName(), false);
        }

        return ResponseEntity.ok(formRenderService.render(id));
    }

    /** Create a form — owner is set to the authenticated user. */
    @PostMapping
    public ResponseEntity<FormEntity> create(@RequestBody FormDTO dto, Authentication auth, HttpSession session) {
        FormEntity created = formService.createForm(dto, auth.getName());
        auditLogService.logEvent(
                "CREATE_FORM",
                auditLogService.getSessionUserId(session.getAttribute("USER_ID")),
                auth.getName(),
                "FORM",
                created.getId().toString(),
                "User '" + auth.getName() + "' created form '" + created.getName() + "'.",
                Map.of("formName", created.getName()),
                null,
                null,
                null,
                null
        );
        return ResponseEntity.status(HttpStatus.CREATED).body(created);
    }

    /** Update — owner or Admin can edit a form. */
    @PutMapping("/{id}")
    public ResponseEntity<FormEntity> update(
            @PathVariable UUID id,
            @RequestBody FormDTO dto,
            Authentication auth,
            HttpSession session) {
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        FormEntity updated = formService.updateForm(id, dto, auth.getName(), isAdmin);
        auditLogService.logEvent(
                "UPDATE_FORM",
                auditLogService.getSessionUserId(session.getAttribute("USER_ID")),
                auth.getName(),
                "FORM",
                updated.getId().toString(),
                "User '" + auth.getName() + "' updated form '" + updated.getName() + "'.",
                Map.of("formName", updated.getName()),
                null,
                null,
                null,
                null
        );
        return ResponseEntity.ok(updated);
    }

    /** Soft-delete — moves form to trash. Owner or Admin. */
    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable UUID id, Authentication auth, HttpSession session) {
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        FormEntity target = formService.getFormForAction(id, auth.getName(), isAdmin);
        formService.deleteForm(id, auth.getName(), isAdmin);
        auditLogService.logEvent(
                "DELETE_FORM",
                auditLogService.getSessionUserId(session.getAttribute("USER_ID")),
                auth.getName(),
                "FORM",
                id.toString(),
                "User '" + auth.getName() + "' deleted form '" + target.getName() + "'.",
                Map.of("formName", target.getName()),
                null,
                null,
                null,
                null
        );
        return ResponseEntity.noContent().build();
    }

    /** List trash — Admin sees all, others see their own. */
    @GetMapping("/trash")
    public ResponseEntity<List<FormEntity>> getTrash(Authentication auth) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        return ResponseEntity.ok(formService.getTrashForms(auth.getName(), isAdmin));
    }

    /** Restore — move a trashed form back to active. Owner or Admin. */
    @PostMapping("/{id}/restore")
    public ResponseEntity<Map<String, Object>> restore(@PathVariable UUID id, Authentication auth) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        FormEntity form = formService.restoreForm(id, auth.getName(), isAdmin);
        return ResponseEntity.ok(Map.of(
                "id", id.toString(),
                "message", "Form restored successfully",
                "name", form.getName()));
    }

    /** Permanently delete — only works if form is already in trash. Owner or Admin. */
    @DeleteMapping("/{id}/permanent")
    public ResponseEntity<Void> permanentDelete(@PathVariable UUID id, Authentication auth) {
        boolean isAdmin = userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
        formService.permanentDeleteForm(id, auth.getName(), isAdmin);
        return ResponseEntity.noContent().build();
    }

    /** Publish — owner or Admin can publish a form. */
    @PatchMapping("/{id}/publish")
    public ResponseEntity<Map<String, Object>> publish(@PathVariable UUID id, Authentication auth, HttpSession session) {
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        FormEntity form = formService.publishForm(id, auth.getName(), isAdmin);
        auditLogService.logEvent(
                "PUBLISH_FORM",
                auditLogService.getSessionUserId(session.getAttribute("USER_ID")),
                auth.getName(),
                "FORM",
                id.toString(),
                "User '" + auth.getName() + "' published form '" + form.getName() + "'.",
                Map.of("formName", form.getName()),
                null,
                null,
                null,
                null
        );
        return ResponseEntity.ok(Map.of(
                "id", id.toString(),
                "status", "PUBLISHED",
                "message", "Form published successfully"));
    }

    /** Unpublish — owner or Admin can unpublish a form. */
    @PatchMapping("/{id}/unpublish")
    public ResponseEntity<Map<String, Object>> unpublish(@PathVariable UUID id, Authentication auth, HttpSession session) {
        Set<String> roles = userRoleService.getUserRoleNames(auth.getName());
        if (roles.contains(ROLE_ROLE_ADMIN)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        boolean isAdmin = roles.contains(ROLE_ADMIN);
        FormEntity form = formService.unpublishForm(id, auth.getName(), isAdmin);
        auditLogService.logEvent(
                "UNPUBLISH_FORM",
                auditLogService.getSessionUserId(session.getAttribute("USER_ID")),
                auth.getName(),
                "FORM",
                id.toString(),
                "User '" + auth.getName() + "' unpublished form '" + form.getName() + "'.",
                Map.of("formName", form.getName()),
                null,
                null,
                null,
                null
        );
        return ResponseEntity.ok(Map.of(
                "id", id.toString(),
                "status", "DRAFT",
                "message", "Form unpublished successfully"));
    }
}

package com.formbuilder.controller;

import com.formbuilder.entity.FormEntity;
import com.formbuilder.rbac.service.UserRoleService;
import com.formbuilder.service.FormService;
import com.formbuilder.service.SubmissionService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;
import org.springframework.web.multipart.MultipartHttpServletRequest;

import jakarta.servlet.http.HttpSession;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.time.LocalDateTime;
import java.util.*;

@Slf4j
@RestController
@RequestMapping("/api/forms")
@RequiredArgsConstructor
public class SubmissionController {

    private final SubmissionService submissionService;
    private final FormService formService;
    private final UserRoleService userRoleService;

    private static final String UPLOAD_DIR = "uploads";

    /**
     * Check form is PUBLISHED, not expired, and enforce single-submission if
     * configured
     */
    private ResponseEntity<?> checkPublishedAndSession(UUID id, HttpSession session) {
        FormEntity form = formService.getFormById(id);
        if (form.getStatus() != FormEntity.FormStatus.PUBLISHED) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("error", "This form is not accepting submissions. It is currently in DRAFT mode."));
        }
        // Expiry check
        if (form.getExpiresAt() != null && LocalDateTime.now().isAfter(form.getExpiresAt())) {
            return ResponseEntity.status(HttpStatus.GONE)
                    .body(Map.of("error", "This form has expired and is no longer accepting submissions."));
        }
        if (!form.isAllowMultipleSubmissions()) {
            String sessionKey = "submitted_" + id;
            if (session.getAttribute(sessionKey) != null) {
                return ResponseEntity.status(HttpStatus.CONFLICT)
                        .body(Map.of("error", "You have already submitted this form. Only one submission is allowed."));
            }
            session.setAttribute(sessionKey, Boolean.TRUE);
        }
        return null;
    }

    /**
     * POST /api/forms/{id}/submit — JSON body
     */
    @PostMapping(value = "/{id}/submit", consumes = { "application/json", "application/json;charset=UTF-8" })
    public ResponseEntity<?> submitJson(
            @PathVariable UUID id,
            @RequestBody(required = false) Map<String, Object> rawBody,
            HttpSession session,
            Authentication auth) {

        ResponseEntity<?> guard = checkPublishedAndSession(id, session);
        if (guard != null)
            return guard;

        Map<String, Object> data = new HashMap<>();
        if (rawBody != null) {
            Object inner = rawBody.get("data");
            if (rawBody.size() == 1 && inner instanceof Map) {
                @SuppressWarnings("unchecked")
                Map<String, Object> wrapped = (Map<String, Object>) inner;
                data.putAll(wrapped);
            } else {
                data.putAll(rawBody);
            }
        }

        log.info("JSON submit — form={} keys={}", id, data.keySet());
        log.debug("JSON submit data: {}", data);

        submissionService.validate(id, data, null);
        submissionService.finalizeSubmission(id, auth != null ? auth.getName() : null, data);
        return ResponseEntity.ok(Map.of("message", "Form submitted successfully"));
    }

    /**
     * GET /api/forms/{id}/draft
     */
    @GetMapping("/{id}/draft")
    public ResponseEntity<?> getDraft(@PathVariable UUID id, Authentication auth) {
        if (auth == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }
        Map<String, Object> draft = submissionService.findDraft(id, auth.getName());
        return ResponseEntity.ok(draft != null ? draft : Map.of());
    }

    /**
     * POST /api/forms/{id}/draft
     */
    @PostMapping("/{id}/draft")
    public ResponseEntity<?> saveDraft(
            @PathVariable UUID id,
            @RequestBody Map<String, Object> rawBody,
            Authentication auth) {
        if (auth == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }

        Map<String, Object> data = new HashMap<>();
        if (rawBody != null) {
            Object inner = rawBody.get("data");
            if (rawBody.size() == 1 && inner instanceof Map) {
                @SuppressWarnings("unchecked")
                Map<String, Object> wrapped = (Map<String, Object>) inner;
                data.putAll(wrapped);
            } else {
                data.putAll(rawBody);
            }
        }

        submissionService.saveDraft(id, auth.getName(), data);
        return ResponseEntity.ok(Map.of("message", "Draft saved successfully", "timestamp", LocalDateTime.now()));
    }

    /**
     * POST /api/forms/{id}/submit — multipart/form-data (file uploads)
     */
    @PostMapping(value = "/{id}/submit", consumes = "multipart/form-data")
    public ResponseEntity<?> submitMultipart(
            @PathVariable UUID id,
            MultipartHttpServletRequest multipart,
            HttpSession session,
            Authentication auth) {

        ResponseEntity<?> guard = checkPublishedAndSession(id, session);
        if (guard != null)
            return guard;

        Map<String, Object> data = new HashMap<>();
        Map<String, MultipartFile> files = new HashMap<>();

        try {
            multipart.getParameterMap().forEach((key, values) -> {
                if (values != null && values.length > 0)
                    data.put(key, values[0]);
            });
            multipart.getMultiFileMap().forEach((key, fileList) -> {
                if (fileList != null && !fileList.isEmpty()) {
                    MultipartFile first = fileList.get(0);
                    if (first != null && !first.isEmpty())
                        files.put(key, first);
                    data.put("__files__" + key, fileList);
                }
            });

            log.info("Multipart submit — form={} fields={} files={}", id, data.size(), files.size());

            submissionService.validate(id, data, files);

            Set<String> savedKeys = new HashSet<>();
            for (Map.Entry<String, Object> entry : new HashMap<>(data).entrySet()) {
                String key = entry.getKey();
                if (!key.startsWith("__files__"))
                    continue;
                String fieldKey = key.substring("__files__".length());
                savedKeys.add(fieldKey);
                @SuppressWarnings("unchecked")
                List<MultipartFile> fileList = (List<MultipartFile>) entry.getValue();
                List<String> savedNames = new ArrayList<>();
                for (MultipartFile f : fileList) {
                    if (f != null && !f.isEmpty())
                        savedNames.add(saveFile(f));
                }
                if (!savedNames.isEmpty())
                    data.put(fieldKey, String.join(",", savedNames));
                data.remove(key);
            }
            for (Map.Entry<String, MultipartFile> e : files.entrySet()) {
                if (!savedKeys.contains(e.getKey()))
                    data.put(e.getKey(), saveFile(e.getValue()));
            }

            submissionService.finalizeSubmission(id, auth != null ? auth.getName() : null, data);
            return ResponseEntity.ok(Map.of("message", "Form submitted successfully"));

        } catch (IOException e) {
            log.error("File save error for form {}", id, e);
            return ResponseEntity.internalServerError()
                    .body(Map.of("error", "Failed to save file: " + e.getMessage()));
        }
    }

    private String saveFile(MultipartFile file) throws IOException {
        Path uploadPath = Paths.get(UPLOAD_DIR);
        if (!Files.exists(uploadPath))
            Files.createDirectories(uploadPath);
        String original = file.getOriginalFilename();
        String extension = (original != null && original.contains("."))
                ? original.substring(original.lastIndexOf('.'))
                : "";
        String unique = UUID.randomUUID() + extension;
        Files.copy(file.getInputStream(), uploadPath.resolve(unique));
        log.info("Saved file: {} (original: {})", unique, original);
        return unique;
    }

    /** Check if the authenticated user has Admin role. */
    private boolean isAdmin(Authentication auth) {
        return userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
    }

    @GetMapping("/{id}/submissions")
    public ResponseEntity<List<Map<String, Object>>> getSubmissions(
            @PathVariable UUID id, Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        return ResponseEntity.ok(submissionService.getSubmissions(id));
    }

    @GetMapping("/{id}/submissions/{submissionId}")
    public ResponseEntity<?> getSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            return ResponseEntity.ok(submissionService.getSubmission(id, submissionId));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }

    @DeleteMapping("/{id}/submissions/{submissionId}")
    public ResponseEntity<?> deleteSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            submissionService.deleteSubmission(id, submissionId);
            return ResponseEntity.ok(Map.of("message", "Submission deleted successfully"));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }

    @PutMapping("/{id}/submissions/{submissionId}")
    public ResponseEntity<?> updateSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            @RequestBody Map<String, Object> data,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        submissionService.validateUpdate(id, data);
        try {
            Map<String, Object> updated = submissionService.updateSubmission(id, submissionId, data);
            return ResponseEntity.ok(updated);
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
        }
    }

    // ── Trash Bin Endpoints ────────────────────────────────────────────────

    /** List all soft-deleted submissions for a form (the trash). */
    @GetMapping("/{id}/submissions/trash")
    public ResponseEntity<?> getTrashSubmissions(
            @PathVariable UUID id,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        return ResponseEntity.ok(submissionService.getTrashSubmissions(id));
    }

    /** Restore a submission from trash back to active. */
    @PostMapping("/{id}/submissions/{submissionId}/restore")
    public ResponseEntity<?> restoreSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            submissionService.restoreSubmission(id, submissionId);
            return ResponseEntity.ok(Map.of("message", "Submission restored successfully"));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }

    /** Permanently delete a submission that is in trash. */
    @DeleteMapping("/{id}/submissions/{submissionId}/permanent")
    public ResponseEntity<?> permanentDeleteSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            submissionService.permanentDeleteSubmission(id, submissionId);
            return ResponseEntity.ok(Map.of("message", "Submission permanently deleted"));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }
}

package com.formbuilder.controller;

import com.formbuilder.entity.FormEntity;
import com.formbuilder.rbac.service.UserRoleService;
import com.formbuilder.service.AuditLogService;
import com.formbuilder.service.FormService;
import com.formbuilder.service.SubmissionService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;
import org.springframework.web.multipart.MultipartHttpServletRequest;

import jakarta.servlet.http.HttpSession;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.time.LocalDateTime;
import java.util.*;

@Slf4j
@RestController
@RequestMapping("/api/forms")
@RequiredArgsConstructor
public class SubmissionController {

    private final SubmissionService submissionService;
    private final FormService formService;
    private final UserRoleService userRoleService;
    private final AuditLogService auditLogService;

    private static final String UPLOAD_DIR = "uploads";

    /**
     * Check form is PUBLISHED, not expired, and enforce single-submission if
     * configured
     */
    private ResponseEntity<?> checkPublishedAndSession(UUID id, HttpSession session) {
        FormEntity form = formService.getFormById(id);
        if (form.getStatus() != FormEntity.FormStatus.PUBLISHED) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("error", "This form is not accepting submissions. It is currently in DRAFT mode."));
        }
        // Expiry check
        if (form.getExpiresAt() != null && LocalDateTime.now().isAfter(form.getExpiresAt())) {
            return ResponseEntity.status(HttpStatus.GONE)
                    .body(Map.of("error", "This form has expired and is no longer accepting submissions."));
        }
        if (!form.isAllowMultipleSubmissions()) {
            String sessionKey = "submitted_" + id;
            if (session.getAttribute(sessionKey) != null) {
                return ResponseEntity.status(HttpStatus.CONFLICT)
                        .body(Map.of("error", "You have already submitted this form. Only one submission is allowed."));
            }
            session.setAttribute(sessionKey, Boolean.TRUE);
        }
        return null;
    }

    /**
     * POST /api/forms/{id}/submit — JSON body
     */
    @PostMapping(value = "/{id}/submit", consumes = { "application/json", "application/json;charset=UTF-8" })
    public ResponseEntity<?> submitJson(
            @PathVariable UUID id,
            @RequestBody(required = false) Map<String, Object> rawBody,
            HttpSession session,
            Authentication auth) {

        ResponseEntity<?> guard = checkPublishedAndSession(id, session);
        if (guard != null)
            return guard;

        Map<String, Object> data = new HashMap<>();
        if (rawBody != null) {
            Object inner = rawBody.get("data");
            if (rawBody.size() == 1 && inner instanceof Map) {
                @SuppressWarnings("unchecked")
                Map<String, Object> wrapped = (Map<String, Object>) inner;
                data.putAll(wrapped);
            } else {
                data.putAll(rawBody);
            }
        }

        log.info("JSON submit — form={} keys={}", id, data.keySet());
        log.debug("JSON submit data: {}", data);

        submissionService.validate(id, data, null);
        submissionService.finalizeSubmission(id, auth != null ? auth.getName() : null, data);

        FormEntity form = formService.getFormById(id);
        String username = auth != null ? auth.getName() : "anonymous";
        auditLogService.logEvent(
                "SUBMIT_FORM",
                auditLogService.getSessionUserId(session.getAttribute("USER_ID")),
                username,
                "FORM",
                id.toString(),
                "User '" + username + "' submitted form '" + form.getName() + "'.",
                Map.of("formName", form.getName()),
                null,
                null,
                null,
                null
        );

        return ResponseEntity.ok(Map.of("message", "Form submitted successfully"));
    }

    /**
     * GET /api/forms/{id}/draft
     */
    @GetMapping("/{id}/draft")
    public ResponseEntity<?> getDraft(@PathVariable UUID id, Authentication auth) {
        if (auth == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }
        Map<String, Object> draft = submissionService.findDraft(id, auth.getName());
        return ResponseEntity.ok(draft != null ? draft : Map.of());
    }

    /**
     * POST /api/forms/{id}/draft
     */
    @PostMapping("/{id}/draft")
    public ResponseEntity<?> saveDraft(
            @PathVariable UUID id,
            @RequestBody Map<String, Object> rawBody,
            Authentication auth) {
        if (auth == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }

        Map<String, Object> data = new HashMap<>();
        if (rawBody != null) {
            Object inner = rawBody.get("data");
            if (rawBody.size() == 1 && inner instanceof Map) {
                @SuppressWarnings("unchecked")
                Map<String, Object> wrapped = (Map<String, Object>) inner;
                data.putAll(wrapped);
            } else {
                data.putAll(rawBody);
            }
        }

        submissionService.saveDraft(id, auth.getName(), data);
        return ResponseEntity.ok(Map.of("message", "Draft saved successfully", "timestamp", LocalDateTime.now()));
    }

    /**
     * POST /api/forms/{id}/submit — multipart/form-data (file uploads)
     */
    @PostMapping(value = "/{id}/submit", consumes = "multipart/form-data")
    public ResponseEntity<?> submitMultipart(
            @PathVariable UUID id,
            MultipartHttpServletRequest multipart,
            HttpSession session,
            Authentication auth) {

        ResponseEntity<?> guard = checkPublishedAndSession(id, session);
        if (guard != null)
            return guard;

        Map<String, Object> data = new HashMap<>();
        Map<String, MultipartFile> files = new HashMap<>();

        try {
            multipart.getParameterMap().forEach((key, values) -> {
                if (values != null && values.length > 0)
                    data.put(key, values[0]);
            });
            multipart.getMultiFileMap().forEach((key, fileList) -> {
                if (fileList != null && !fileList.isEmpty()) {
                    MultipartFile first = fileList.get(0);
                    if (first != null && !first.isEmpty())
                        files.put(key, first);
                    data.put("__files__" + key, fileList);
                }
            });

            log.info("Multipart submit — form={} fields={} files={}", id, data.size(), files.size());

            submissionService.validate(id, data, files);

            Set<String> savedKeys = new HashSet<>();
            for (Map.Entry<String, Object> entry : new HashMap<>(data).entrySet()) {
                String key = entry.getKey();
                if (!key.startsWith("__files__"))
                    continue;
                String fieldKey = key.substring("__files__".length());
                savedKeys.add(fieldKey);
                @SuppressWarnings("unchecked")
                List<MultipartFile> fileList = (List<MultipartFile>) entry.getValue();
                List<String> savedNames = new ArrayList<>();
                for (MultipartFile f : fileList) {
                    if (f != null && !f.isEmpty())
                        savedNames.add(saveFile(f));
                }
                if (!savedNames.isEmpty())
                    data.put(fieldKey, String.join(",", savedNames));
                data.remove(key);
            }
            for (Map.Entry<String, MultipartFile> e : files.entrySet()) {
                if (!savedKeys.contains(e.getKey()))
                    data.put(e.getKey(), saveFile(e.getValue()));
            }

            submissionService.finalizeSubmission(id, auth != null ? auth.getName() : null, data);

            FormEntity form = formService.getFormById(id);
            String username = auth != null ? auth.getName() : "anonymous";
            auditLogService.logEvent(
                    "SUBMIT_FORM",
                    auditLogService.getSessionUserId(session.getAttribute("USER_ID")),
                    username,
                    "FORM",
                    id.toString(),
                    "User '" + username + "' submitted form '" + form.getName() + "'.",
                    Map.of("formName", form.getName()),
                    null,
                    null,
                    null,
                    null
            );

            return ResponseEntity.ok(Map.of("message", "Form submitted successfully"));

        } catch (IOException e) {
            log.error("File save error for form {}", id, e);
            return ResponseEntity.internalServerError()
                    .body(Map.of("error", "Failed to save file: " + e.getMessage()));
        }
    }

    private String saveFile(MultipartFile file) throws IOException {
        Path uploadPath = Paths.get(UPLOAD_DIR);
        if (!Files.exists(uploadPath))
            Files.createDirectories(uploadPath);
        String original = file.getOriginalFilename();
        String extension = (original != null && original.contains("."))
                ? original.substring(original.lastIndexOf('.'))
                : "";
        String unique = UUID.randomUUID() + extension;
        Files.copy(file.getInputStream(), uploadPath.resolve(unique));
        log.info("Saved file: {} (original: {})", unique, original);
        return unique;
    }

    /** Check if the authenticated user has Admin role. */
    private boolean isAdmin(Authentication auth) {
        return userRoleService.getUserRoleNames(auth.getName()).contains("Admin");
    }

    @GetMapping("/{id}/submissions")
    public ResponseEntity<List<Map<String, Object>>> getSubmissions(
            @PathVariable UUID id, Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        return ResponseEntity.ok(submissionService.getSubmissions(id));
    }

    @GetMapping("/{id}/submissions/{submissionId}")
    public ResponseEntity<?> getSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            return ResponseEntity.ok(submissionService.getSubmission(id, submissionId));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }

    @DeleteMapping("/{id}/submissions/{submissionId}")
    public ResponseEntity<?> deleteSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            submissionService.deleteSubmission(id, submissionId);
            return ResponseEntity.ok(Map.of("message", "Submission deleted successfully"));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }

    @PutMapping("/{id}/submissions/{submissionId}")
    public ResponseEntity<?> updateSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            @RequestBody Map<String, Object> data,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        submissionService.validateUpdate(id, data);
        try {
            Map<String, Object> updated = submissionService.updateSubmission(id, submissionId, data);
            return ResponseEntity.ok(updated);
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
        }
    }

    // ── Trash Bin Endpoints ────────────────────────────────────────────────

    /** List all soft-deleted submissions for a form (the trash). */
    @GetMapping("/{id}/submissions/trash")
    public ResponseEntity<?> getTrashSubmissions(
            @PathVariable UUID id,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        return ResponseEntity.ok(submissionService.getTrashSubmissions(id));
    }

    /** Restore a submission from trash back to active. */
    @PostMapping("/{id}/submissions/{submissionId}/restore")
    public ResponseEntity<?> restoreSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            submissionService.restoreSubmission(id, submissionId);
            return ResponseEntity.ok(Map.of("message", "Submission restored successfully"));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }

    /** Permanently delete a submission that is in trash. */
    @DeleteMapping("/{id}/submissions/{submissionId}/permanent")
    public ResponseEntity<?> permanentDeleteSubmission(
            @PathVariable UUID id,
            @PathVariable UUID submissionId,
            Authentication auth) {
        formService.getFormForAction(id, auth.getName(), isAdmin(auth));
        try {
            submissionService.permanentDeleteSubmission(id, submissionId);
            return ResponseEntity.ok(Map.of("message", "Submission permanently deleted"));
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }
}

package com.formbuilder.rbac.controller;

import com.formbuilder.rbac.entity.Permission;
import com.formbuilder.rbac.entity.Role;
import com.formbuilder.rbac.security.RequirePermission;
import com.formbuilder.rbac.service.RoleService;
import jakarta.servlet.http.HttpSession;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.*;

/**
 * REST Controller for Role management.
 *
 * All endpoints require the MANAGE permission — enforced by
 * {@code @RequirePermission("MANAGE")} at class level, which is
 * checked by the {@link com.formbuilder.rbac.security.PermissionInterceptor}
 * before any handler method executes.
 *
 * <pre>
 * GET    /api/roles              → list all roles with their permissions
 * POST   /api/roles              → create a custom role
 * PUT    /api/roles/{id}         → update a custom role (name and/or permissions)
 * DELETE /api/roles/{id}         → delete a custom role (system roles are protected)
 * POST   /api/roles/{id}/permissions → add permissions to an existing role
 * </pre>
 */
@Slf4j
@RestController
@RequestMapping("/api/roles")
@RequiredArgsConstructor
@RequirePermission("MANAGE")
public class RoleController {

    private final RoleService roleService;

    // ── GET /api/roles ───────────────────────────────────────────────────

    /**
     * Returns all roles (system + custom) with their assigned permissions.
     * System roles appear first, then alphabetical.
     */
    @GetMapping
    public ResponseEntity<?> getAllRoles() {
        List<Role> roles = roleService.getAllRoles();

        List<Map<String, Object>> response = roles.stream()
                .map(this::toRoleResponse)
                .toList();

        return ResponseEntity.ok(response);
    }

    // ── POST /api/roles ──────────────────────────────────────────────────

    /**
     * Creates a new custom role.
     *
     * Request body:
     * <pre>
     * {
     *   "name": "Regional Auditor",
     *   "permissions": ["READ", "EXPORT", "AUDIT"]
     * }
     * </pre>
     *
     * Validations (enforced by RoleService):
     * 1. Role name must be unique
     * 4. Actor cannot assign permissions they don't hold
     */
    @PostMapping
    public ResponseEntity<?> createRole(@RequestBody CreateRoleRequest body,
                                        Authentication auth,
                                        HttpSession session) {

        // Validate request body
        if (body.name == null || body.name.trim().isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "Role name is required"));
        }
        if (body.permissions == null || body.permissions.isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "At least one permission is required"));
        }

        Integer actorUserId = (Integer) session.getAttribute("USER_ID");
        String actorUsername = auth.getName();

        Role created = roleService.createRole(
                body.name,
                new LinkedHashSet<>(body.permissions),
                actorUsername,
                actorUserId
        );

        // Reload with permissions for response
        Role loaded = roleService.getRoleWithPermissions(created.getId());

        return ResponseEntity.status(HttpStatus.CREATED)
                .body(toRoleResponse(loaded));
    }

    // ── PUT /api/roles/{id} ──────────────────────────────────────────────

    /**
     * Updates a custom role's name and/or permissions.
     *
     * Request body:
     * <pre>
     * {
     *   "name": "Updated Name",         // optional — null keeps existing
     *   "permissions": ["READ", "WRITE"] // optional — null keeps existing
     * }
     * </pre>
     *
     * Validations (enforced by RoleService):
     * 1. Role name must be unique (if changed)
     * 2. System roles cannot be edited
     * 4. Actor cannot assign permissions they don't hold
     */
    @PutMapping("/{id}")
    public ResponseEntity<?> updateRole(@PathVariable Integer id,
                                        @RequestBody UpdateRoleRequest body,
                                        Authentication auth) {

        Set<String> permKeys = body.permissions != null
                ? new LinkedHashSet<>(body.permissions)
                : null;

        Role updated = roleService.updateRole(id, body.name, permKeys, auth.getName());

        // Reload with permissions for response
        Role loaded = roleService.getRoleWithPermissions(updated.getId());

        return ResponseEntity.ok(toRoleResponse(loaded));
    }

    // ── DELETE /api/roles/{id} ───────────────────────────────────────────

    /**
     * Deletes a custom role. System roles are protected.
     *
     * Validations (enforced by RoleService):
     * 3. System roles cannot be deleted
     */
    @DeleteMapping("/{id}")
    public ResponseEntity<?> deleteRole(@PathVariable Integer id,
                                        Authentication auth) {

        roleService.deleteRole(id, auth.getName());

        return ResponseEntity.ok(Map.of("message", "Role deleted successfully"));
    }

    // ── POST /api/roles/{id}/permissions ─────────────────────────────────

    /**
     * Adds permissions to an existing custom role (additive — does not remove
     * existing permissions).
     *
     * Request body:
     * <pre>
     * {
     *   "permissions": ["EXPORT", "AUDIT"]
     * }
     * </pre>
     *
     * Validations (enforced by RoleService):
     * 2. System roles cannot be edited
     * 4. Actor cannot assign permissions they don't hold
     */
    @PostMapping("/{id}/permissions")
    public ResponseEntity<?> assignPermissions(@PathVariable Integer id,
                                               @RequestBody PermissionsRequest body,
                                               Authentication auth) {

        if (body.permissions == null || body.permissions.isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "At least one permission is required"));
        }

        Role updated = roleService.assignPermissionsToRole(
                id,
                new LinkedHashSet<>(body.permissions),
                auth.getName()
        );

        // Reload with permissions for response
        Role loaded = roleService.getRoleWithPermissions(updated.getId());

        return ResponseEntity.ok(toRoleResponse(loaded));
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  RESPONSE BUILDER
    // ═══════════════════════════════════════════════════════════════════════

    /**
     * Converts a Role entity to a clean JSON-friendly map.
     * Avoids exposing JPA internals / lazy proxy objects.
     */
    private Map<String, Object> toRoleResponse(Role role) {
        Map<String, Object> map = new LinkedHashMap<>();
        map.put("id", role.getId());
        map.put("roleName", role.getRoleName());
        map.put("isSystemRole", role.isSystemRole());
        map.put("createdBy", role.getCreatedBy());
        map.put("createdAt", role.getCreatedAt());
        map.put("updatedAt", role.getUpdatedAt());
        map.put("permissions", role.getPermissions().stream()
                .map(Permission::getPermissionKey)
                .sorted()
                .toList());
        return map;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  REQUEST DTOs (inner classes — scoped to this controller only)
    // ═══════════════════════════════════════════════════════════════════════

    /** POST /api/roles request body. */
    public static class CreateRoleRequest {
        public String name;
        public List<String> permissions;
    }

    /** PUT /api/roles/{id} request body. */
    public static class UpdateRoleRequest {
        public String name;
        public List<String> permissions;
    }

    /** POST /api/roles/{id}/permissions request body. */
    public static class PermissionsRequest {
        public List<String> permissions;
    }
}

package com.formbuilder.rbac.controller;

import com.formbuilder.rbac.entity.Permission;
import com.formbuilder.rbac.entity.Role;
import com.formbuilder.rbac.security.RequirePermission;
import com.formbuilder.rbac.service.RoleService;
import com.formbuilder.service.AuditLogService;
import jakarta.servlet.http.HttpSession;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.*;

/**
 * REST Controller for Role management.
 *
 * All endpoints require the MANAGE permission — enforced by
 * {@code @RequirePermission("MANAGE")} at class level, which is
 * checked by the {@link com.formbuilder.rbac.security.PermissionInterceptor}
 * before any handler method executes.
 *
 * <pre>
 * GET    /api/roles              → list all roles with their permissions
 * POST   /api/roles              → create a custom role
 * PUT    /api/roles/{id}         → update a custom role (name and/or permissions)
 * DELETE /api/roles/{id}         → delete a custom role (system roles are protected)
 * POST   /api/roles/{id}/permissions → add permissions to an existing role
 * </pre>
 */
@Slf4j
@RestController
@RequestMapping("/api/roles")
@RequiredArgsConstructor
@RequirePermission("MANAGE")
public class RoleController {

    private final RoleService roleService;
    private final AuditLogService auditLogService;

    // ── GET /api/roles ───────────────────────────────────────────────────

    /**
     * Returns all roles (system + custom) with their assigned permissions.
     * System roles appear first, then alphabetical.
     */
    @GetMapping
    public ResponseEntity<?> getAllRoles() {
        List<Role> roles = roleService.getAllRoles();

        List<Map<String, Object>> response = roles.stream()
                .map(this::toRoleResponse)
                .toList();

        return ResponseEntity.ok(response);
    }

    // ── POST /api/roles ──────────────────────────────────────────────────

    /**
     * Creates a new custom role.
     *
     * Request body:
     * <pre>
     * {
     *   "name": "Regional Auditor",
     *   "permissions": ["READ", "EXPORT", "AUDIT"]
     * }
     * </pre>
     *
     * Validations (enforced by RoleService):
     * 1. Role name must be unique
     * 4. Actor cannot assign permissions they don't hold
     */
    @PostMapping
    public ResponseEntity<?> createRole(@RequestBody CreateRoleRequest body,
                                        Authentication auth,
                                        HttpSession session) {

        // Validate request body
        if (body.name == null || body.name.trim().isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "Role name is required"));
        }
        if (body.permissions == null || body.permissions.isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "At least one permission is required"));
        }

        Integer actorUserId = (Integer) session.getAttribute("USER_ID");
        String actorUsername = auth.getName();

        Role created = roleService.createRole(
                body.name,
                new LinkedHashSet<>(body.permissions),
                actorUsername,
                actorUserId
        );

        // Reload with permissions for response
        Role loaded = roleService.getRoleWithPermissions(created.getId());

        auditLogService.logEvent(
                "CREATE_ROLE",
                actorUserId,
                actorUsername,
                "ROLE",
                loaded.getId().toString(),
                "User '" + actorUsername + "' created role '" + loaded.getRoleName() + "'.",
                Map.of("permissions", loaded.getPermissions().stream().map(Permission::getPermissionKey).sorted().toList()),
                loaded.getId(),
                loaded.getRoleName(),
                null,
                null
        );

        return ResponseEntity.status(HttpStatus.CREATED)
                .body(toRoleResponse(loaded));
    }

    // ── PUT /api/roles/{id} ──────────────────────────────────────────────

    /**
     * Updates a custom role's name and/or permissions.
     *
     * Request body:
     * <pre>
     * {
     *   "name": "Updated Name",         // optional — null keeps existing
     *   "permissions": ["READ", "WRITE"] // optional — null keeps existing
     * }
     * </pre>
     *
     * Validations (enforced by RoleService):
     * 1. Role name must be unique (if changed)
     * 2. System roles cannot be edited
     * 4. Actor cannot assign permissions they don't hold
     */
    @PutMapping("/{id}")
    public ResponseEntity<?> updateRole(@PathVariable Integer id,
                                        @RequestBody UpdateRoleRequest body,
                                        Authentication auth,
                                        HttpSession session) {

        Set<String> permKeys = body.permissions != null
                ? new LinkedHashSet<>(body.permissions)
                : null;

        Role updated = roleService.updateRole(id, body.name, permKeys, auth.getName());

        // Reload with permissions for response
        Role loaded = roleService.getRoleWithPermissions(updated.getId());

        auditLogService.logEvent(
                "UPDATE_ROLE",
                (Integer) session.getAttribute("USER_ID"),
                auth.getName(),
                "ROLE",
                loaded.getId().toString(),
                "User '" + auth.getName() + "' updated role '" + loaded.getRoleName() + "'.",
                Map.of("permissions", loaded.getPermissions().stream().map(Permission::getPermissionKey).sorted().toList()),
                loaded.getId(),
                loaded.getRoleName(),
                null,
                null
        );

        return ResponseEntity.ok(toRoleResponse(loaded));
    }

    // ── DELETE /api/roles/{id} ───────────────────────────────────────────

    /**
     * Deletes a custom role. System roles are protected.
     *
     * Validations (enforced by RoleService):
     * 3. System roles cannot be deleted
     */
    @DeleteMapping("/{id}")
    public ResponseEntity<?> deleteRole(@PathVariable Integer id,
                                        Authentication auth,
                                        HttpSession session) {

        Role roleBeforeDelete = roleService.getRoleWithPermissions(id);

        roleService.deleteRole(id, auth.getName());

        auditLogService.logEvent(
                "DELETE_ROLE",
                (Integer) session.getAttribute("USER_ID"),
                auth.getName(),
                "ROLE",
                id.toString(),
                "User '" + auth.getName() + "' deleted role '" + roleBeforeDelete.getRoleName() + "'.",
                null,
                roleBeforeDelete.getId(),
                roleBeforeDelete.getRoleName(),
                null,
                null
        );

        return ResponseEntity.ok(Map.of("message", "Role deleted successfully"));
    }

    // ── POST /api/roles/{id}/permissions ─────────────────────────────────

    /**
     * Adds permissions to an existing custom role (additive — does not remove
     * existing permissions).
     *
     * Request body:
     * <pre>
     * {
     *   "permissions": ["EXPORT", "AUDIT"]
     * }
     * </pre>
     *
     * Validations (enforced by RoleService):
     * 2. System roles cannot be edited
     * 4. Actor cannot assign permissions they don't hold
     */
    @PostMapping("/{id}/permissions")
    public ResponseEntity<?> assignPermissions(@PathVariable Integer id,
                                               @RequestBody PermissionsRequest body,
                                               Authentication auth,
                                               HttpSession session) {

        if (body.permissions == null || body.permissions.isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "At least one permission is required"));
        }

        Role updated = roleService.assignPermissionsToRole(
                id,
                new LinkedHashSet<>(body.permissions),
                auth.getName()
        );

        // Reload with permissions for response
        Role loaded = roleService.getRoleWithPermissions(updated.getId());

        auditLogService.logEvent(
                "UPDATE_PERMISSION",
                (Integer) session.getAttribute("USER_ID"),
                auth.getName(),
                "ROLE",
                loaded.getId().toString(),
                "User '" + auth.getName() + "' updated permissions for role '" + loaded.getRoleName() + "'.",
                Map.of("permissions", loaded.getPermissions().stream().map(Permission::getPermissionKey).sorted().toList()),
                loaded.getId(),
                loaded.getRoleName(),
                null,
                null
        );

        return ResponseEntity.ok(toRoleResponse(loaded));
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  RESPONSE BUILDER
    // ═══════════════════════════════════════════════════════════════════════

    /**
     * Converts a Role entity to a clean JSON-friendly map.
     * Avoids exposing JPA internals / lazy proxy objects.
     */
    private Map<String, Object> toRoleResponse(Role role) {
        Map<String, Object> map = new LinkedHashMap<>();
        map.put("id", role.getId());
        map.put("roleName", role.getRoleName());
        map.put("isSystemRole", role.isSystemRole());
        map.put("createdBy", role.getCreatedBy());
        map.put("createdAt", role.getCreatedAt());
        map.put("updatedAt", role.getUpdatedAt());
        map.put("permissions", role.getPermissions().stream()
                .map(Permission::getPermissionKey)
                .sorted()
                .toList());
        return map;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  REQUEST DTOs (inner classes — scoped to this controller only)
    // ═══════════════════════════════════════════════════════════════════════

    /** POST /api/roles request body. */
    public static class CreateRoleRequest {
        public String name;
        public List<String> permissions;
    }

    /** PUT /api/roles/{id} request body. */
    public static class UpdateRoleRequest {
        public String name;
        public List<String> permissions;
    }

    /** POST /api/roles/{id}/permissions request body. */
    public static class PermissionsRequest {
        public List<String> permissions;
    }
}

package com.formbuilder.rbac.controller;

import com.formbuilder.rbac.entity.Permission;
import com.formbuilder.rbac.entity.User;
import com.formbuilder.rbac.security.RequirePermission;
import com.formbuilder.rbac.service.UserRoleService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.*;

/**
 * REST Controller for RBAC user management and role assignment.
 *
 * All endpoints require the MANAGE permission — enforced by
 * {@code @RequirePermission("MANAGE")} at class level via
 * {@link com.formbuilder.rbac.security.PermissionInterceptor}.
 *
 * <pre>
 * GET    /api/users                    → list all RBAC users with their roles
 * POST   /api/users                    → create an RBAC user profile
 * PUT    /api/users/{id}               → update user name/email
 * DELETE /api/users/{id}               → delete RBAC user profile
 * POST   /api/users/{id}/roles         → assign a role to a user
 * DELETE /api/users/{id}/roles/{roleId}→ remove a role from a user
 * GET    /api/users/{id}/permissions   → get effective permissions for a user
 * </pre>
 */
@Slf4j
@RestController
@RequestMapping("/api/users")
@RequiredArgsConstructor
@RequirePermission("MANAGE")
public class UserController {

    private final UserRoleService userRoleService;

    // ── GET /api/users ───────────────────────────────────────────────────

    /**
     * Returns all RBAC users with their assigned roles.
     * Excludes the currently logged-in user from the list.
     * If the requesting user is a Role Administrator (not Admin),
     * also excludes users who have the Admin role.
     */
    @GetMapping
    public ResponseEntity<?> getAllUsers(Authentication auth) {
        List<User> users = userRoleService.getAllUsers();

        String currentUsername = auth != null ? auth.getName() : null;
        Set<String> myRoles = currentUsername != null
                ? userRoleService.getUserRoleNames(currentUsername)
                : Set.of();
        boolean iAmAdmin = myRoles.contains("Admin");

        List<Map<String, Object>> response = users.stream()
                .filter(u -> !u.getUsername().equals(currentUsername))
                // Role Administrator cannot see Admin or other Role Administrator users
                .filter(u -> {
                    if (iAmAdmin) return true; // Admin sees everyone
                    // Check if this user has Admin or Role Administrator role
                    boolean userIsAdmin = u.getRoles().stream()
                            .anyMatch(r -> r.getRoleName().equals("Admin") || r.getRoleName().equals("Role Administrator"));
                    return !userIsAdmin;
                })
                .map(this::toUserResponse)
                .toList();

        return ResponseEntity.ok(response);
    }

    // ── POST /api/users ──────────────────────────────────────────────────

    /**
     * Creates a new RBAC user profile.
     * The username must already exist in the Spring Security 'users' table
     * (registered via /api/auth/register).
     *
     * Request body:
     * <pre>
     * {
     *   "username": "john_doe",
     *   "name": "John Doe",
     *   "email": "john@example.com"
     * }
     * </pre>
     */
    @PostMapping
    public ResponseEntity<?> createUser(@RequestBody CreateUserRequest body) {

        if (body.username == null || body.username.trim().isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "Username is required"));
        }

        User created = userRoleService.createUser(body.username, body.name, body.email);

        return ResponseEntity.status(HttpStatus.CREATED)
                .body(toUserResponse(created));
    }

    // ── PUT /api/users/{id} ──────────────────────────────────────────────

    /**
     * Updates an RBAC user's display name and/or email.
     *
     * Request body:
     * <pre>
     * {
     *   "name": "John Updated",
     *   "email": "john.updated@example.com"
     * }
     * </pre>
     */
    @PutMapping("/{id}")
    public ResponseEntity<?> updateUser(@PathVariable Integer id,
                                        @RequestBody UpdateUserRequest body) {

        User updated = userRoleService.updateUser(id, body.name, body.email);

        return ResponseEntity.ok(toUserResponse(updated));
    }

    // ── DELETE /api/users/{id} ───────────────────────────────────────────

    /**
     * Deletes an RBAC user profile. CASCADE in DB handles user_roles cleanup.
     */
    @DeleteMapping("/{id}")
    public ResponseEntity<?> deleteUser(@PathVariable Integer id) {

        userRoleService.deleteUser(id);

        return ResponseEntity.ok(Map.of("message", "User deleted successfully"));
    }

    // ── POST /api/users/{id}/roles ───────────────────────────────────────

    /**
     * Assigns a role to a user.
     *
     * Request body:
     * <pre>
     * {
     *   "roleId": 3
     * }
     * </pre>
     *
     * Uses INSERT INTO user_roles(user_id, role_id) VALUES (?, ?)
     * ON CONFLICT DO NOTHING — idempotent.
     */
    @PostMapping("/{id}/roles")
    public ResponseEntity<?> assignRole(@PathVariable Integer id,
                                        @RequestBody AssignRoleRequest body) {

        if (body.roleId == null) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "roleId is required"));
        }

        User updated = userRoleService.assignRoleToUserById(id, body.roleId);

        return ResponseEntity.ok(toUserResponse(updated));
    }

    // ── DELETE /api/users/{id}/roles/{roleId} ────────────────────────────

    /**
     * Removes a role from a user.
     */
    @DeleteMapping("/{id}/roles/{roleId}")
    public ResponseEntity<?> removeRole(@PathVariable Integer id,
                                        @PathVariable Integer roleId) {

        User updated = userRoleService.removeRoleFromUserById(id, roleId);

        return ResponseEntity.ok(toUserResponse(updated));
    }

    // ── GET /api/users/{id}/permissions ──────────────────────────────────

    /**
     * Returns the effective permissions for a user — the union of all
     * permissions across all assigned roles.
     *
     * Response:
     * <pre>
     * {
     *   "permissions": ["APPROVE", "READ", "WRITE"]
     * }
     * </pre>
     */
    @GetMapping("/{id}/permissions")
    public ResponseEntity<?> getUserPermissions(@PathVariable Integer id) {

        Set<String> permissionKeys = userRoleService.getUserPermissionKeysById(id);

        return ResponseEntity.ok(Map.of(
                "permissions", permissionKeys.stream().sorted().toList()
        ));
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  RESPONSE BUILDER
    // ═══════════════════════════════════════════════════════════════════════

    /**
     * Converts a User entity to a clean JSON-friendly map.
     * Avoids exposing JPA internals / lazy proxy objects.
     */
    private Map<String, Object> toUserResponse(User user) {
        Map<String, Object> map = new LinkedHashMap<>();
        map.put("id", user.getId());
        map.put("username", user.getUsername());
        map.put("name", user.getName());
        map.put("email", user.getEmail());
        map.put("createdAt", user.getCreatedAt());
        map.put("roles", user.getRoles().stream()
                .map(role -> {
                    Map<String, Object> r = new LinkedHashMap<>();
                    r.put("id", role.getId());
                    r.put("roleName", role.getRoleName());
                    r.put("isSystemRole", role.isSystemRole());
                    r.put("permissions", role.getPermissions().stream()
                            .map(Permission::getPermissionKey)
                            .sorted()
                            .toList());
                    return r;
                })
                .sorted(Comparator.comparing(r -> (String) r.get("roleName")))
                .toList());
        // Also include flattened effective permissions
        map.put("permissions", user.getRoles().stream()
                .flatMap(role -> role.getPermissions().stream())
                .map(Permission::getPermissionKey)
                .distinct()
                .sorted()
                .toList());
        return map;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  REQUEST DTOs
    // ═══════════════════════════════════════════════════════════════════════

    /** POST /api/users request body. */
    public static class CreateUserRequest {
        public String username;
        public String name;
        public String email;
    }

    /** PUT /api/users/{id} request body. */
    public static class UpdateUserRequest {
        public String name;
        public String email;
    }

    /** POST /api/users/{id}/roles request body. */
    public static class AssignRoleRequest {
        public Integer roleId;
    }
}

package com.formbuilder.rbac.controller;

import com.formbuilder.rbac.entity.Permission;
import com.formbuilder.rbac.entity.User;
import com.formbuilder.rbac.security.RequirePermission;
import com.formbuilder.rbac.service.UserRoleService;
import com.formbuilder.service.AuditLogService;
import jakarta.servlet.http.HttpSession;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.*;

/**
 * REST Controller for RBAC user management and role assignment.
 *
 * All endpoints require the MANAGE permission — enforced by
 * {@code @RequirePermission("MANAGE")} at class level via
 * {@link com.formbuilder.rbac.security.PermissionInterceptor}.
 *
 * <pre>
 * GET    /api/users                    → list all RBAC users with their roles
 * POST   /api/users                    → create an RBAC user profile
 * PUT    /api/users/{id}               → update user name/email
 * DELETE /api/users/{id}               → delete RBAC user profile
 * POST   /api/users/{id}/roles         → assign a role to a user
 * DELETE /api/users/{id}/roles/{roleId}→ remove a role from a user
 * GET    /api/users/{id}/permissions   → get effective permissions for a user
 * </pre>
 */
@Slf4j
@RestController
@RequestMapping("/api/users")
@RequiredArgsConstructor
@RequirePermission("MANAGE")
public class UserController {

    private final UserRoleService userRoleService;
    private final AuditLogService auditLogService;

    // ── GET /api/users ───────────────────────────────────────────────────

    /**
     * Returns all RBAC users with their assigned roles.
     * Excludes the currently logged-in user from the list.
     * If the requesting user is a Role Administrator (not Admin),
     * also excludes users who have the Admin role.
     */
    @GetMapping
    public ResponseEntity<?> getAllUsers(Authentication auth) {
        List<User> users = userRoleService.getAllUsers();

        String currentUsername = auth != null ? auth.getName() : null;
        Set<String> myRoles = currentUsername != null
                ? userRoleService.getUserRoleNames(currentUsername)
                : Set.of();
        boolean iAmAdmin = myRoles.contains("Admin");

        List<Map<String, Object>> response = users.stream()
                .filter(u -> !u.getUsername().equals(currentUsername))
                // Role Administrator cannot see Admin or other Role Administrator users
                .filter(u -> {
                    if (iAmAdmin) return true; // Admin sees everyone
                    // Check if this user has Admin or Role Administrator role
                    boolean userIsAdmin = u.getRoles().stream()
                            .anyMatch(r -> r.getRoleName().equals("Admin") || r.getRoleName().equals("Role Administrator"));
                    return !userIsAdmin;
                })
                .map(this::toUserResponse)
                .toList();

        return ResponseEntity.ok(response);
    }

    // ── POST /api/users ──────────────────────────────────────────────────

    /**
     * Creates a new RBAC user profile.
     * The username must already exist in the Spring Security 'users' table
     * (registered via /api/auth/register).
     *
     * Request body:
     * <pre>
     * {
     *   "username": "john_doe",
     *   "name": "John Doe",
     *   "email": "john@example.com"
     * }
     * </pre>
     */
    @PostMapping
    public ResponseEntity<?> createUser(@RequestBody CreateUserRequest body) {

        if (body.username == null || body.username.trim().isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "Username is required"));
        }

        User created = userRoleService.createUser(body.username, body.name, body.email);

        return ResponseEntity.status(HttpStatus.CREATED)
                .body(toUserResponse(created));
    }

    // ── PUT /api/users/{id} ──────────────────────────────────────────────

    /**
     * Updates an RBAC user's display name and/or email.
     *
     * Request body:
     * <pre>
     * {
     *   "name": "John Updated",
     *   "email": "john.updated@example.com"
     * }
     * </pre>
     */
    @PutMapping("/{id}")
    public ResponseEntity<?> updateUser(@PathVariable Integer id,
                                        @RequestBody UpdateUserRequest body) {

        User updated = userRoleService.updateUser(id, body.name, body.email);

        return ResponseEntity.ok(toUserResponse(updated));
    }

    // ── DELETE /api/users/{id} ───────────────────────────────────────────

    /**
     * Deletes an RBAC user profile. CASCADE in DB handles user_roles cleanup.
     */
    @DeleteMapping("/{id}")
    public ResponseEntity<?> deleteUser(@PathVariable Integer id) {

        userRoleService.deleteUser(id);

        return ResponseEntity.ok(Map.of("message", "User deleted successfully"));
    }

    // ── POST /api/users/{id}/roles ───────────────────────────────────────

    /**
     * Assigns a role to a user.
     *
     * Request body:
     * <pre>
     * {
     *   "roleId": 3
     * }
     * </pre>
     *
     * Uses INSERT INTO user_roles(user_id, role_id) VALUES (?, ?)
     * ON CONFLICT DO NOTHING — idempotent.
     */
    @PostMapping("/{id}/roles")
    public ResponseEntity<?> assignRole(@PathVariable Integer id,
                                        @RequestBody AssignRoleRequest body,
                                        Authentication auth,
                                        HttpSession session) {

        if (body.roleId == null) {
            return ResponseEntity.badRequest()
                    .body(Map.of("error", "roleId is required"));
        }

        User before = userRoleService.getUserById(id);
        Integer oldRoleId = before.getRoles().stream().findFirst().map(r -> r.getId()).orElse(null);
        String oldRoleName = before.getRoles().stream().findFirst().map(r -> r.getRoleName()).orElse(null);

        User updated = userRoleService.assignRoleToUserById(id, body.roleId);

        Integer newRoleId = updated.getRoles().stream().findFirst().map(r -> r.getId()).orElse(null);
        String newRoleName = updated.getRoles().stream().findFirst().map(r -> r.getRoleName()).orElse("Unknown");

        if (!Objects.equals(oldRoleId, newRoleId)) {
            Map<String, Object> metadata = new LinkedHashMap<>();
            metadata.put("oldRoleId", oldRoleId);
            metadata.put("oldRoleName", oldRoleName);
            metadata.put("newRoleId", newRoleId);
            metadata.put("newRoleName", newRoleName);

            auditLogService.logEvent(
                    "ASSIGN_ROLE",
                    (Integer) session.getAttribute("USER_ID"),
                    auth.getName(),
                    "USER",
                    id.toString(),
                    "User '" + auth.getName() + "' changed role for user '" + updated.getUsername() +
                            "' from '" + (oldRoleName == null ? "None" : oldRoleName) + "' to '" + newRoleName + "'.",
                    metadata,
                    newRoleId,
                    newRoleName,
                    updated.getId(),
                    updated.getUsername()
            );
        }

        return ResponseEntity.ok(toUserResponse(updated));
    }

    // ── DELETE /api/users/{id}/roles/{roleId} ────────────────────────────

    /**
     * Removes a role from a user.
     */
    @DeleteMapping("/{id}/roles/{roleId}")
    public ResponseEntity<?> removeRole(@PathVariable Integer id,
                                        @PathVariable Integer roleId,
                                        Authentication auth,
                                        HttpSession session) {

        User updated = userRoleService.removeRoleFromUserById(id, roleId);

        auditLogService.logEvent(
                "REMOVE_ROLE",
                (Integer) session.getAttribute("USER_ID"),
                auth.getName(),
                "USER",
                id.toString(),
                "User '" + auth.getName() + "' removed role id '" + roleId + "' from user '" + updated.getUsername() + "'.",
                Map.of("roleId", roleId),
                roleId,
                null,
                updated.getId(),
                updated.getUsername()
        );

        return ResponseEntity.ok(toUserResponse(updated));
    }

    // ── GET /api/users/{id}/permissions ──────────────────────────────────

    /**
     * Returns the effective permissions for a user — the union of all
     * permissions across all assigned roles.
     *
     * Response:
     * <pre>
     * {
     *   "permissions": ["APPROVE", "READ", "WRITE"]
     * }
     * </pre>
     */
    @GetMapping("/{id}/permissions")
    public ResponseEntity<?> getUserPermissions(@PathVariable Integer id) {

        Set<String> permissionKeys = userRoleService.getUserPermissionKeysById(id);

        return ResponseEntity.ok(Map.of(
                "permissions", permissionKeys.stream().sorted().toList()
        ));
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  RESPONSE BUILDER
    // ═══════════════════════════════════════════════════════════════════════

    /**
     * Converts a User entity to a clean JSON-friendly map.
     * Avoids exposing JPA internals / lazy proxy objects.
     */
    private Map<String, Object> toUserResponse(User user) {
        Map<String, Object> map = new LinkedHashMap<>();
        map.put("id", user.getId());
        map.put("username", user.getUsername());
        map.put("name", user.getName());
        map.put("email", user.getEmail());
        map.put("createdAt", user.getCreatedAt());
        map.put("roles", user.getRoles().stream()
                .map(role -> {
                    Map<String, Object> r = new LinkedHashMap<>();
                    r.put("id", role.getId());
                    r.put("roleName", role.getRoleName());
                    r.put("isSystemRole", role.isSystemRole());
                    r.put("permissions", role.getPermissions().stream()
                            .map(Permission::getPermissionKey)
                            .sorted()
                            .toList());
                    return r;
                })
                .sorted(Comparator.comparing(r -> (String) r.get("roleName")))
                .toList());
        // Also include flattened effective permissions
        map.put("permissions", user.getRoles().stream()
                .flatMap(role -> role.getPermissions().stream())
                .map(Permission::getPermissionKey)
                .distinct()
                .sorted()
                .toList());
        return map;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  REQUEST DTOs
    // ═══════════════════════════════════════════════════════════════════════

    /** POST /api/users request body. */
    public static class CreateUserRequest {
        public String username;
        public String name;
        public String email;
    }

    /** PUT /api/users/{id} request body. */
    public static class UpdateUserRequest {
        public String name;
        public String email;
    }

    /** POST /api/users/{id}/roles request body. */
    public static class AssignRoleRequest {
        public Integer roleId;
    }
}

package com.formbuilder.rbac.service;

import com.formbuilder.rbac.entity.Permission;
import com.formbuilder.rbac.entity.Role;
import com.formbuilder.rbac.entity.User;
import com.formbuilder.rbac.repository.RoleRepository;
import com.formbuilder.rbac.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;
import java.util.stream.Collectors;

/**
 * Service for managing RBAC user profiles, user ↔ role assignments,
 * and querying a user's effective roles and permissions.
 *
 * This service works with the RBAC user profile (rbac_users table),
 * NOT the Spring Security users table directly.
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class UserRoleService {

    private final UserRepository userRepo;
    private final RoleRepository roleRepo;
    private final JdbcTemplate jdbc;

    // ═══════════════════════════════════════════════════════════════════════
    //  USER CRUD
    // ═══════════════════════════════════════════════════════════════════════

    /** Returns all RBAC users with roles + permissions eagerly loaded. */
    public List<User> getAllUsers() {
        return userRepo.findAllWithRolesAndPermissions();
    }

    /** Returns a single user with roles + permissions eagerly loaded. */
    public User getUserById(Integer id) {
        return userRepo.findByIdWithRolesAndPermissions(id)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + id));
    }

    /**
     * Creates a new RBAC user profile with credentials.
     * If password is null/empty, a random password is generated
     * (user must use password reset to set their own).
     */
    @Transactional
    public User createUser(String username, String name, String email) {
        if (username == null || username.trim().isEmpty()) {
            throw new IllegalArgumentException("Username is required");
        }
        if (userRepo.existsByUsername(username.trim())) {
            throw new IllegalArgumentException("User profile already exists for username: " + username);
        }
        if (email != null && !email.trim().isEmpty() && userRepo.existsByEmail(email.trim())) {
            throw new IllegalArgumentException("Email already in use: " + email);
        }

        User user = User.builder()
                .username(username.trim())
                .password("")  // No password — admin-created profiles need the user to register or reset
                .name(name != null ? name.trim() : null)
                .email(email != null && !email.trim().isEmpty() ? email.trim() : null)
                .enabled(true)
                .build();

        User saved = userRepo.save(user);
        log.info("RBAC user profile created for '{}'", username);
        return saved;
    }

    /** Updates an RBAC user's name and/or email. */
    @Transactional
    public User updateUser(Integer id, String name, String email) {
        User user = userRepo.findById(id)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + id));

        if (name != null) {
            user.setName(name.trim());
        }
        if (email != null) {
            String trimmedEmail = email.trim();
            if (!trimmedEmail.isEmpty()) {
                // Check uniqueness only if email changed
                if (!trimmedEmail.equals(user.getEmail()) && userRepo.existsByEmail(trimmedEmail)) {
                    throw new IllegalArgumentException("Email already in use: " + trimmedEmail);
                }
                user.setEmail(trimmedEmail);
            } else {
                user.setEmail(null);
            }
        }

        User saved = userRepo.save(user);
        log.info("RBAC user profile updated for '{}' (id={})", user.getUsername(), id);
        return saved;
    }

    /** Deletes an RBAC user profile. CASCADE in DB handles user_roles cleanup. */
    @Transactional
    public void deleteUser(Integer id) {
        User user = userRepo.findById(id)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + id));
        userRepo.delete(user);
        log.info("RBAC user profile deleted for '{}' (id={})", user.getUsername(), id);
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  ASSIGN ROLE TO USER (by user ID)
    // ═══════════════════════════════════════════════════════════════════════

    /**
     * Assigns a role to a user by user ID.
     * Uses ON CONFLICT DO NOTHING semantics via the unique constraint.
     */
    @Transactional
    public User assignRoleToUserById(Integer userId, Integer roleId) {
        User user = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        // ON CONFLICT DO NOTHING — idempotent via direct SQL
        jdbc.update("INSERT INTO user_roles(user_id, role_id) VALUES (?, ?) ON CONFLICT DO NOTHING",
                userId, roleId);

        // Reload to get fresh state
        User reloaded = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        log.info("Role '{}' assigned to user '{}' (id={})", role.getRoleName(), user.getUsername(), userId);
        return reloaded;
    }

    /**
     * Removes a role from a user by user ID.
     */
    @Transactional
    public User removeRoleFromUserById(Integer userId, Integer roleId) {
        User user = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        boolean removed = user.getRoles().removeIf(r -> r.getId().equals(roleId));

        if (!removed) {
            throw new IllegalArgumentException(
                    "User '" + user.getUsername() + "' does not have role '" + role.getRoleName() + "'");
        }

        User saved = userRepo.save(user);
        log.info("Role '{}' removed from user '{}' (id={})", role.getRoleName(), user.getUsername(), userId);
        return saved;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  ASSIGN ROLE TO USER (by username — kept for backward compatibility)
    // ═══════════════════════════════════════════════════════════════════════

    @Transactional
    public User assignRoleToUser(String username, Integer roleId) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username
                                + ". Ensure the user has a profile in rbac_users."));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        boolean alreadyAssigned = user.getRoles().stream()
                .anyMatch(r -> r.getId().equals(roleId));

        if (alreadyAssigned) {
            throw new IllegalArgumentException(
                    "User '" + username + "' already has role '" + role.getRoleName() + "'");
        }

        user.getRoles().add(role);
        User saved = userRepo.save(user);

        log.info("Role '{}' assigned to user '{}'", role.getRoleName(), username);
        return saved;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  REMOVE ROLE FROM USER (by username — kept for backward compatibility)
    // ═══════════════════════════════════════════════════════════════════════

    @Transactional
    public User removeRoleFromUser(String username, Integer roleId) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        boolean removed = user.getRoles().removeIf(r -> r.getId().equals(roleId));

        if (!removed) {
            throw new IllegalArgumentException(
                    "User '" + username + "' does not have role '" + role.getRoleName() + "'");
        }

        User saved = userRepo.save(user);
        log.info("Role '{}' removed from user '{}'", role.getRoleName(), username);
        return saved;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  READ — USER ROLES
    // ═══════════════════════════════════════════════════════════════════════

    public Set<Role> getUserRoles(String username) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username));
        return user.getRoles();
    }

    public Set<String> getUserRoleNames(String username) {
        return getUserRoles(username).stream()
                .map(Role::getRoleName)
                .collect(Collectors.toSet());
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  READ — USER PERMISSIONS (effective, union across all roles)
    // ═══════════════════════════════════════════════════════════════════════

    public Set<Permission> getUserPermissions(String username) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username));

        return user.getRoles().stream()
                .flatMap(role -> role.getPermissions().stream())
                .collect(Collectors.toSet());
    }

    /** Returns effective permissions for a user by ID. */
    public Set<Permission> getUserPermissionsById(Integer userId) {
        User user = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        return user.getRoles().stream()
                .flatMap(role -> role.getPermissions().stream())
                .collect(Collectors.toSet());
    }

    public Set<String> getUserPermissionKeys(String username) {
        return getUserPermissions(username).stream()
                .map(Permission::getPermissionKey)
                .collect(Collectors.toSet());
    }

    /** Returns effective permission key strings for a user by ID. */
    public Set<String> getUserPermissionKeysById(Integer userId) {
        return getUserPermissionsById(userId).stream()
                .map(Permission::getPermissionKey)
                .collect(Collectors.toSet());
    }

    public boolean userHasPermission(String username, String permissionKey) {
        try {
            return getUserPermissionKeys(username).contains(permissionKey);
        } catch (NoSuchElementException e) {
            log.warn("Permission check for unknown RBAC user '{}' — denied", username);
            return false;
        }
    }

    public boolean userHasRole(String username, String roleName) {
        try {
            return getUserRoleNames(username).contains(roleName);
        } catch (NoSuchElementException e) {
            return false;
        }
    }
}

package com.formbuilder.rbac.service;

import com.formbuilder.rbac.entity.Permission;
import com.formbuilder.rbac.entity.Role;
import com.formbuilder.rbac.entity.User;
import com.formbuilder.rbac.repository.RoleRepository;
import com.formbuilder.rbac.repository.UserRepository;
import jakarta.persistence.EntityManager;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;
import java.util.stream.Collectors;

/**
 * Service for managing RBAC user profiles, user ↔ role assignments,
 * and querying a user's effective roles and permissions.
 *
 * This service works with the RBAC user profile (rbac_users table),
 * NOT the Spring Security users table directly.
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class UserRoleService {

    private final UserRepository userRepo;
    private final RoleRepository roleRepo;
    private final JdbcTemplate jdbc;
    private final EntityManager entityManager;

    // ═══════════════════════════════════════════════════════════════════════
    //  USER CRUD
    // ═══════════════════════════════════════════════════════════════════════

    /** Returns all RBAC users with roles + permissions eagerly loaded. */
    public List<User> getAllUsers() {
        return userRepo.findAllWithRolesAndPermissions();
    }

    /** Returns a single user with roles + permissions eagerly loaded. */
    public User getUserById(Integer id) {
        return userRepo.findByIdWithRolesAndPermissions(id)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + id));
    }

    /**
     * Creates a new RBAC user profile with credentials.
     * If password is null/empty, a random password is generated
     * (user must use password reset to set their own).
     */
    @Transactional
    public User createUser(String username, String name, String email) {
        if (username == null || username.trim().isEmpty()) {
            throw new IllegalArgumentException("Username is required");
        }
        if (userRepo.existsByUsername(username.trim())) {
            throw new IllegalArgumentException("User profile already exists for username: " + username);
        }
        if (email != null && !email.trim().isEmpty() && userRepo.existsByEmail(email.trim())) {
            throw new IllegalArgumentException("Email already in use: " + email);
        }

        User user = User.builder()
                .username(username.trim())
                .password("")  // No password — admin-created profiles need the user to register or reset
                .name(name != null ? name.trim() : null)
                .email(email != null && !email.trim().isEmpty() ? email.trim() : null)
                .enabled(true)
                .build();

        User saved = userRepo.save(user);
        log.info("RBAC user profile created for '{}'", username);
        return saved;
    }

    /** Updates an RBAC user's name and/or email. */
    @Transactional
    public User updateUser(Integer id, String name, String email) {
        User user = userRepo.findById(id)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + id));

        if (name != null) {
            user.setName(name.trim());
        }
        if (email != null) {
            String trimmedEmail = email.trim();
            if (!trimmedEmail.isEmpty()) {
                // Check uniqueness only if email changed
                if (!trimmedEmail.equals(user.getEmail()) && userRepo.existsByEmail(trimmedEmail)) {
                    throw new IllegalArgumentException("Email already in use: " + trimmedEmail);
                }
                user.setEmail(trimmedEmail);
            } else {
                user.setEmail(null);
            }
        }

        User saved = userRepo.save(user);
        log.info("RBAC user profile updated for '{}' (id={})", user.getUsername(), id);
        return saved;
    }

    /** Deletes an RBAC user profile. CASCADE in DB handles user_roles cleanup. */
    @Transactional
    public void deleteUser(Integer id) {
        User user = userRepo.findById(id)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + id));
        userRepo.delete(user);
        log.info("RBAC user profile deleted for '{}' (id={})", user.getUsername(), id);
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  ASSIGN ROLE TO USER (by user ID)
    // ═══════════════════════════════════════════════════════════════════════

    /**
     * Assigns exactly one role to a user by user ID.
     * Existing role assignments are replaced so each user has a single role.
     */
    @Transactional
    public User assignRoleToUserById(Integer userId, Integer roleId) {
        User user = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        Role currentRole = user.getRoles().stream().findFirst().orElse(null);
        if (currentRole != null && currentRole.getId().equals(roleId)) {
            log.debug("Role '{}' is already assigned to user '{}' (id={}) — skipping", role.getRoleName(), user.getUsername(), userId);
            return user;
        }

        // Enforce single-role policy: replace any existing role assignment.
        jdbc.update("DELETE FROM user_roles WHERE user_id = ?", userId);
        jdbc.update("INSERT INTO user_roles(user_id, role_id) VALUES (?, ?)", userId, roleId);

        // JDBC writes bypass JPA tracking; clear 1st-level cache so re-query sees latest role.
        entityManager.clear();

        // Reload to get fresh state
        User reloaded = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        log.info("Role '{}' assigned to user '{}' (id={})", role.getRoleName(), user.getUsername(), userId);
        return reloaded;
    }

    /**
     * Removes a role from a user by user ID.
     * Single-role policy requires at least one role, so removing the current
     * role is not allowed via this endpoint.
     */
    @Transactional
    public User removeRoleFromUserById(Integer userId, Integer roleId) {
        User user = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        if (user.getRoles().size() <= 1) {
            throw new IllegalArgumentException("Each user must have exactly one role. Assign a new role instead.");
        }

        boolean removed = user.getRoles().removeIf(r -> r.getId().equals(roleId));

        if (!removed) {
            throw new IllegalArgumentException(
                    "User '" + user.getUsername() + "' does not have role '" + role.getRoleName() + "'");
        }

        User saved = userRepo.save(user);
        log.info("Role '{}' removed from user '{}' (id={})", role.getRoleName(), user.getUsername(), userId);
        return saved;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  ASSIGN ROLE TO USER (by username — kept for backward compatibility)
    // ═══════════════════════════════════════════════════════════════════════

    /**
     * Backward-compatible username path, now enforcing single-role policy.
     */
    @Transactional
    public User assignRoleToUser(String username, Integer roleId) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username
                                + ". Ensure the user has a profile in rbac_users."));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        Role currentRole = user.getRoles().stream().findFirst().orElse(null);
        if (currentRole != null && currentRole.getId().equals(roleId)) {
            log.debug("Role '{}' is already assigned to user '{}' — skipping", role.getRoleName(), username);
            return user;
        }

        user.getRoles().clear();
        user.getRoles().add(role);
        User saved = userRepo.save(user);

        log.info("Role '{}' assigned to user '{}'", role.getRoleName(), username);
        return saved;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  REMOVE ROLE FROM USER (by username — kept for backward compatibility)
    // ═══════════════════════════════════════════════════════════════════════

    @Transactional
    public User removeRoleFromUser(String username, Integer roleId) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username));

        Role role = roleRepo.findById(roleId)
                .orElseThrow(() -> new NoSuchElementException("Role not found: " + roleId));

        if (user.getRoles().size() <= 1) {
            throw new IllegalArgumentException("Each user must have exactly one role. Assign a new role instead.");
        }

        boolean removed = user.getRoles().removeIf(r -> r.getId().equals(roleId));

        if (!removed) {
            throw new IllegalArgumentException(
                    "User '" + username + "' does not have role '" + role.getRoleName() + "'");
        }

        User saved = userRepo.save(user);
        log.info("Role '{}' removed from user '{}'", role.getRoleName(), username);
        return saved;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  READ — USER ROLES
    // ═══════════════════════════════════════════════════════════════════════

    public Set<Role> getUserRoles(String username) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username));
        return user.getRoles();
    }

    public Set<String> getUserRoleNames(String username) {
        return getUserRoles(username).stream()
                .map(Role::getRoleName)
                .collect(Collectors.toSet());
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  READ — USER PERMISSIONS (effective, union across all roles)
    // ═══════════════════════════════════════════════════════════════════════

    public Set<Permission> getUserPermissions(String username) {
        User user = userRepo.findByUsernameWithRolesAndPermissions(username)
                .orElseThrow(() -> new NoSuchElementException(
                        "RBAC user not found: " + username));

        return user.getRoles().stream()
                .flatMap(role -> role.getPermissions().stream())
                .collect(Collectors.toSet());
    }

    /** Returns effective permissions for a user by ID. */
    public Set<Permission> getUserPermissionsById(Integer userId) {
        User user = userRepo.findByIdWithRolesAndPermissions(userId)
                .orElseThrow(() -> new NoSuchElementException("User not found: " + userId));

        return user.getRoles().stream()
                .flatMap(role -> role.getPermissions().stream())
                .collect(Collectors.toSet());
    }

    public Set<String> getUserPermissionKeys(String username) {
        return getUserPermissions(username).stream()
                .map(Permission::getPermissionKey)
                .collect(Collectors.toSet());
    }

    /** Returns effective permission key strings for a user by ID. */
    public Set<String> getUserPermissionKeysById(Integer userId) {
        return getUserPermissionsById(userId).stream()
                .map(Permission::getPermissionKey)
                .collect(Collectors.toSet());
    }

    public boolean userHasPermission(String username, String permissionKey) {
        try {
            return getUserPermissionKeys(username).contains(permissionKey);
        } catch (NoSuchElementException e) {
            log.warn("Permission check for unknown RBAC user '{}' — denied", username);
            return false;
        }
    }

    public boolean userHasRole(String username, String roleName) {
        try {
            return getUserRoleNames(username).contains(roleName);
        } catch (NoSuchElementException e) {
            return false;
        }
    }
}

package com.formbuilder.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Service;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.concurrent.atomic.AtomicBoolean;

@Slf4j
@Service
@RequiredArgsConstructor
public class AuditLogService {

    private final JdbcTemplate jdbc;
    private final ObjectMapper objectMapper;
    private final AtomicBoolean ensured = new AtomicBoolean(false);

    private void ensureAuditLogStore() {
        if (ensured.get()) {
            return;
        }
        synchronized (ensured) {
            if (ensured.get()) {
                return;
            }
            jdbc.execute("CREATE TABLE IF NOT EXISTS audit_logs (" +
                    "id BIGSERIAL PRIMARY KEY, " +
                    "action VARCHAR(60) NOT NULL, " +
                    "performed_by_user_id INT, " +
                    "performed_by_username VARCHAR(100) NOT NULL, " +
                    "target_entity VARCHAR(30) NOT NULL, " +
                    "target_entity_id VARCHAR(100), " +
                    "description TEXT NOT NULL, " +
                    "created_at TIMESTAMP NOT NULL DEFAULT NOW(), " +
                    "metadata JSONB, " +
                    "related_role_id INT, " +
                    "related_role_name VARCHAR(100), " +
                    "related_user_id INT, " +
                    "related_username VARCHAR(100))");
            jdbc.execute("CREATE INDEX IF NOT EXISTS idx_audit_logs_created_at ON audit_logs(created_at)");
            jdbc.execute("CREATE INDEX IF NOT EXISTS idx_audit_logs_action ON audit_logs(action)");
            jdbc.execute("CREATE INDEX IF NOT EXISTS idx_audit_logs_performed_by ON audit_logs(performed_by_username)");
            jdbc.execute("CREATE INDEX IF NOT EXISTS idx_audit_logs_role ON audit_logs(related_role_id)");
            jdbc.execute("CREATE INDEX IF NOT EXISTS idx_audit_logs_user ON audit_logs(related_user_id)");
            ensured.set(true);
        }
    }

    public void logEvent(
            String action,
            Integer performedByUserId,
            String performedByUsername,
            String targetEntity,
            String targetEntityId,
            String description,
            Map<String, Object> metadata,
            Integer relatedRoleId,
            String relatedRoleName,
            Integer relatedUserId,
            String relatedUsername) {

        try {
            ensureAuditLogStore();
            String metadataJson = metadata == null || metadata.isEmpty() ? null : objectMapper.writeValueAsString(metadata);
            jdbc.update(
                    "INSERT INTO audit_logs (" +
                            "action, performed_by_user_id, performed_by_username, target_entity, target_entity_id, description, metadata, " +
                            "related_role_id, related_role_name, related_user_id, related_username" +
                            ") VALUES (?, ?, ?, ?, ?, ?, ?::jsonb, ?, ?, ?, ?)",
                    action,
                    performedByUserId,
                    performedByUsername == null || performedByUsername.isBlank() ? "unknown" : performedByUsername,
                    targetEntity,
                    targetEntityId,
                    description,
                    metadataJson,
                    relatedRoleId,
                    relatedRoleName,
                    relatedUserId,
                    relatedUsername
            );
        } catch (JsonProcessingException e) {
            log.warn("Audit log metadata serialization failed for action {}: {}", action, e.getMessage());
        } catch (Exception e) {
            // Never break business flow because audit logging failed.
            log.warn("Audit logging failed for action {}: {}", action, e.getMessage());
        }
    }

    public List<Map<String, Object>> getAdminLogs(String action, String user, LocalDate fromDate, LocalDate toDate) {
        ensureAuditLogStore();
        StringBuilder sql = new StringBuilder(
                "SELECT id, action, performed_by_user_id, performed_by_username, target_entity, target_entity_id, " +
                        "description, created_at, metadata " +
                        "FROM audit_logs WHERE 1=1");

        List<Object> params = new ArrayList<>();

        if (action != null && !action.isBlank()) {
            sql.append(" AND action = ?");
            params.add(action.trim());
        }
        if (user != null && !user.isBlank()) {
            sql.append(" AND performed_by_username ILIKE ?");
            params.add("%" + user.trim() + "%");
        }
        if (fromDate != null) {
            sql.append(" AND created_at >= ?");
            params.add(fromDate.atStartOfDay());
        }
        if (toDate != null) {
            sql.append(" AND created_at < ?");
            params.add(toDate.plusDays(1).atStartOfDay());
        }

        sql.append(" ORDER BY created_at DESC");
        return jdbc.queryForList(sql.toString(), params.toArray());
    }

    public List<Map<String, Object>> getRoleAssignmentLogs(Integer roleId, String username, LocalDate fromDate, LocalDate toDate) {
        ensureAuditLogStore();
        StringBuilder sql = new StringBuilder(
                "SELECT id, action, created_at, performed_by_username, description, " +
                        "related_role_id, related_role_name, related_user_id, related_username " +
                        "FROM audit_logs " +
                        "WHERE action IN ('ASSIGN_ROLE', 'REMOVE_ROLE', 'UPDATE_PERMISSION')");

        List<Object> params = new ArrayList<>();

        if (roleId != null) {
            sql.append(" AND related_role_id = ?");
            params.add(roleId);
        }
        if (username != null && !username.isBlank()) {
            sql.append(" AND related_username ILIKE ?");
            params.add("%" + username.trim() + "%");
        }
        if (fromDate != null) {
            sql.append(" AND created_at >= ?");
            params.add(fromDate.atStartOfDay());
        }
        if (toDate != null) {
            sql.append(" AND created_at < ?");
            params.add(toDate.plusDays(1).atStartOfDay());
        }

        sql.append(" ORDER BY created_at DESC");
        return jdbc.queryForList(sql.toString(), params.toArray());
    }

    public Integer getSessionUserId(Object sessionUserId) {
        if (sessionUserId instanceof Integer) {
            return (Integer) sessionUserId;
        }
        return null;
    }

    public LocalDateTime now() {
        return LocalDateTime.now();
    }
}

package com.formbuilder.service;

import com.formbuilder.dto.FormDTO;
import com.formbuilder.dto.FormFieldDTO;
import com.formbuilder.entity.FormEntity;
import com.formbuilder.entity.FormFieldEntity;
import com.formbuilder.entity.FormGroupEntity;
import com.formbuilder.entity.SharedOptionsEntity;
import com.formbuilder.entity.StaticFormFieldEntity;
import com.formbuilder.repository.FormFieldJpaRepository;
import com.formbuilder.repository.FormGroupRepository;
import com.formbuilder.repository.FormJpaRepository;
import com.formbuilder.repository.SharedOptionsRepository;
import com.formbuilder.repository.StaticFormFieldRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class FormService {

    private final FormJpaRepository formRepo;
    private final FormFieldJpaRepository fieldRepo;
    private final SharedOptionsRepository sharedOptionsRepo;
    private final StaticFormFieldRepository staticRepo;
    private final FormGroupRepository groupRepo;
    private final DynamicTableService dynamicTable;

    // ── Read ──────────────────────────────────────────────────────────────────

    /** Returns only forms owned by the given user (legacy — kept for backward compatibility). */
    public List<FormEntity> getAllForms(String owner) {
        return formRepo.findAllByCreatedByOrderByCreatedAtDesc(owner);
    }

    /**
     * Returns forms visible to the user based on their RBAC roles.
     *
     * Role visibility matrix:
     * - Admin:              ALL non-deleted forms
     * - Role Administrator: ALL non-deleted PUBLISHED forms
     * - Builder:            ONLY their own forms (any status) — not other builders' forms
     * - Others:             PUBLISHED forms filtered by allowed_roles
     *
     * allowed_roles filtering:
     *   If form.allowed_roles is NULL/empty → visible to everyone (default/PUBLIC)
     *   If form.allowed_roles is set → only users with a matching role can see it
     *   Admin & Role Administrator always bypass allowed_roles
     */
    public List<FormEntity> getFormsForRole(String username, Set<String> roleNames) {
        // Admin sees everything
        if (roleNames.contains("Admin")) {
            return formRepo.findAllByOrderByCreatedAtDesc();
        }

        // Role Administrator sees all published forms
        if (roleNames.contains("Role Administrator")) {
            return formRepo.findPublishedPublicForms();
        }

        // Builder sees ONLY their own forms (any status) — not other builders' forms
        if (roleNames.contains("Builder")) {
            return formRepo.findAllByCreatedByOrderByCreatedAtDesc(username);
        }

        // All other roles: get published forms, then filter by allowed_roles
        List<FormEntity> published = formRepo.findPublishedAccessibleForms();
        return filterByAllowedRoles(published, roleNames);
    }

    /**
     * Filters a list of forms by the allowed_roles JSON column.
     * If allowed_roles is null/empty → form is visible to everyone.
     * If allowed_roles contains role names → user must have at least one matching role.
     */
    private List<FormEntity> filterByAllowedRoles(List<FormEntity> forms, Set<String> userRoles) {
        return forms.stream().filter(form -> {
            String json = form.getAllowedRoles();
            if (json == null || json.isBlank() || json.equals("[]")) {
                return true; // no restriction → visible to all
            }
            List<String> allowed = deserializeRoleList(json);
            if (allowed.isEmpty()) return true;
            // User must have at least one of the allowed roles
            return allowed.stream().anyMatch(userRoles::contains);
        }).collect(Collectors.toList());
    }

    /** Deserialize JSON array string to List<String>. */
    private List<String> deserializeRoleList(String json) {
        if (json == null || json.isBlank()) return List.of();
        try {
            return new com.fasterxml.jackson.databind.ObjectMapper()
                    .readValue(json, new com.fasterxml.jackson.core.type.TypeReference<List<String>>() {});
        } catch (Exception e) {
            log.warn("Failed to parse allowed_roles JSON: {}", json);
            return List.of();
        }
    }

    /** Serialize List<String> to JSON array string. */
    private String serializeRoleList(List<String> roles) {
        if (roles == null || roles.isEmpty()) return null;
        try {
            return new com.fasterxml.jackson.databind.ObjectMapper().writeValueAsString(roles);
        } catch (Exception e) {
            return null;
        }
    }

    /**
     * Returns a form by ID — any owner (used by public endpoints like
     * submit/render).
     */
    public FormEntity getFormById(UUID id) {
        return formRepo.findByIdWithFields(id)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    /**
     * Returns a form by ID scoped to the authenticated owner.
     * Throws NoSuchElementException (→ 404) if form doesn't exist OR belongs to
     * someone else.
     */
    public FormEntity getOwnedFormById(UUID id, String owner) {
        return formRepo.findByIdAndCreatedBy(id, owner)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    /**
     * Returns a form by ID — allows access if the user is the owner OR has Admin role.
     * Used by edit, delete, publish, unpublish, render/admin endpoints.
     */
    public FormEntity getFormForAction(UUID id, String username, boolean isAdmin) {
        if (isAdmin) {
            return formRepo.findByIdWithFields(id)
                    .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
        }
        return formRepo.findByIdAndCreatedBy(id, username)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    /**
     * Returns a form by ID (including soft-deleted) — allows access if owner OR Admin.
     * Used by restore and permanent-delete.
     */
    public FormEntity getFormForActionIncludingTrashed(UUID id, String username, boolean isAdmin) {
        if (isAdmin) {
            return formRepo.findById(id)
                    .map(f -> {
                        // Force-load fields for consistency
                        f.getFields().size();
                        return f;
                    })
                    .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
        }
        return formRepo.findByIdAndCreatedByIncludingTrashed(id, username)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    // ── Create ────────────────────────────────────────────────────────────────

    @Transactional
    public FormEntity createForm(FormDTO dto, String owner) {
        validateUniqueFieldKeys(dto.getFields());
        String tableName = dynamicTable.generateTableName(dto.getName());

        FormEntity form = FormEntity.builder()
                .name(dto.getName())
                .description(dto.getDescription())
                .tableName(tableName)
                .createdBy(owner)
                .visibility(parseVisibility(dto.getVisibility()))
                .allowedRoles(serializeRoleList(dto.getAllowedRoles()))
                .allowMultipleSubmissions(
                        dto.getAllowMultipleSubmissions() == null ? true : dto.getAllowMultipleSubmissions())
                .showTimestamp(true) // always compulsory — timestamp every submission
                .expiresAt(dto.getExpiresAt())
                .fields(new ArrayList<>())
                .build();

        // 1. Initial save of form metadata (to get form.id)
        FormEntity saved = formRepo.save(form);

        // 2. Save static fields (no FK dependencies)
        saveStaticFields(saved.getId(), dto.getStaticFields());

        // 3. Save groups (must exist before dynamic fields reference them)
        saveGroups(saved.getId(), dto.getGroups());
        groupRepo.flush(); // Force groups to DB before saving fields

        // 4. Map and save dynamic fields
        if (dto.getFields() != null) {
            for (FormFieldDTO f : dto.getFields()) {
                saved.getFields().add(toFieldEntity(f, saved));
            }
            // Save again to flush fields with correct IDs
            saved = formRepo.save(saved);
        }

        dynamicTable.createTable(tableName, saved.getFields());

        log.info("Form '{}' created by '{}' with table '{}'", saved.getName(), owner, tableName);
        return saved;
    }

    // ── Update ────────────────────────────────────────────────────────────────

    @Transactional
    public FormEntity updateForm(UUID id, FormDTO dto, String owner, boolean isAdmin) {
        validateUniqueFieldKeys(dto.getFields());

        FormEntity existing = getFormForAction(id, owner, isAdmin);

        Map<String, FormFieldEntity> oldByKey = existing.getFields().stream()
                .collect(Collectors.toMap(FormFieldEntity::getFieldKey, f -> f));

        Set<String> newKeys = dto.getFields() != null
                ? dto.getFields().stream().map(FormFieldDTO::getFieldKey).collect(Collectors.toSet())
                : Set.of();

        // DDL: add / alter columns
        if (dto.getFields() != null) {
            for (FormFieldDTO f : dto.getFields()) {
                if (!oldByKey.containsKey(f.getFieldKey())) {
                    dynamicTable.addColumn(existing.getTableName(), f.getFieldKey(), f.getFieldType());
                } else {
                    String oldType = oldByKey.get(f.getFieldKey()).getFieldType();
                    if (!oldType.equals(f.getFieldType())) {
                        dynamicTable.alterColumnType(existing.getTableName(), f.getFieldKey(), f.getFieldType());
                    }
                }
            }
        }
        // DDL: drop removed columns
        for (String key : oldByKey.keySet()) {
            if (!newKeys.contains(key)) {
                dynamicTable.dropColumn(existing.getTableName(), key);
            }
        }

        // 1. Replace all static fields
        staticRepo.deleteByFormId(existing.getId());
        saveStaticFields(existing.getId(), dto.getStaticFields());

        // 2. Replace all groups (must exist before fields reference them)
        groupRepo.deleteByFormId(existing.getId());
        groupRepo.flush(); // Force delete to DB
        saveGroups(existing.getId(), dto.getGroups());
        groupRepo.flush(); // Force inserts to DB

        // 3. Update form metadata and fields
        existing.setName(dto.getName());
        existing.setDescription(dto.getDescription());
        if (dto.getVisibility() != null) {
            existing.setVisibility(parseVisibility(dto.getVisibility()));
        }
        if (dto.getAllowedRoles() != null) {
            existing.setAllowedRoles(serializeRoleList(dto.getAllowedRoles()));
        }
        if (dto.getAllowMultipleSubmissions() != null)
            existing.setAllowMultipleSubmissions(dto.getAllowMultipleSubmissions());
        existing.setExpiresAt(dto.getExpiresAt());
        existing.getFields().removeIf(field -> !newKeys.contains(field.getFieldKey()));

        if (dto.getFields() != null) {
            for (FormFieldDTO dtoField : dto.getFields()) {
                FormFieldEntity existingField = oldByKey.get(dtoField.getFieldKey());
                if (existingField != null) {
                    existingField.setLabel(dtoField.getLabel());
                    existingField.setFieldType(dtoField.getFieldType());
                    existingField.setRequired(dtoField.isRequired());
                    existingField.setDefaultValue(dtoField.getDefaultValue());
                    existingField.setValidationRegex(dtoField.getValidationRegex());
                    existingField.setValidationJson(dtoField.getValidationJson());
                    existingField.setRulesJson(dtoField.getRulesJson());
                    existingField.setUiConfigJson(dtoField.getUiConfigJson());
                    existingField.setSharedOptionsId(dtoField.getSharedOptionsId());
                    existingField.setFieldOrder(dtoField.getFieldOrder());
                    existingField.setDisabled(dtoField.isDisabled());
                    existingField.setReadOnly(dtoField.isReadOnly());
                    existingField.setIsCalculated(dtoField.getIsCalculated());
                    existingField.setFormulaExpression(dtoField.getFormulaExpression());
                    existingField.setDependenciesJson(serializeDependencies(dtoField.getDependencies()));
                    existingField.setPrecision(dtoField.getPrecision());
                    existingField.setLockAfterCalculation(dtoField.getLockAfterCalculation());
                    existingField.setParentGroupKey(dtoField.getParentGroupKey());
                    existingField.setGroupId(dtoField.getGroupId());
                } else {
                    existing.getFields().add(toFieldEntity(dtoField, existing));
                }
            }
        }

        return formRepo.save(existing);
    }

    // ── Delete / Soft Delete / Trash ────────────────────────────────────────────

    /**
     * Soft-delete: mark the form as deleted without removing data.
     * The form disappears from all active listings and appears in the trash.
     */
    @Transactional
    public void deleteForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForAction(id, owner, isAdmin);
        form.setSoftDeleted(true);
        form.setDeletedAt(java.time.LocalDateTime.now());
        formRepo.save(form);
        log.info("Form '{}' soft-deleted by '{}'", form.getName(), owner);
    }

    /** Returns soft-deleted forms — Admin sees all, others see only their own. */
    public List<FormEntity> getTrashForms(String owner, boolean isAdmin) {
        if (isAdmin) {
            return formRepo.findAllTrashed();
        }
        return formRepo.findTrashedByOwner(owner);
    }

    /** Restore a soft-deleted form back to active. */
    @Transactional
    public FormEntity restoreForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForActionIncludingTrashed(id, owner, isAdmin);
        form.setSoftDeleted(false);
        form.setDeletedAt(null);
        FormEntity saved = formRepo.save(form);
        log.info("Form '{}' restored by '{}'", form.getName(), owner);
        return saved;
    }

    /** Permanently delete a soft-deleted form and drop its submission table. */
    @Transactional
    public void permanentDeleteForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForActionIncludingTrashed(id, owner, isAdmin);
        if (!form.isSoftDeleted()) {
            throw new IllegalStateException("Form must be in trash before permanent deletion");
        }
        dynamicTable.dropTable(form.getTableName());
        formRepo.delete(form);
        log.info("Form '{}' permanently deleted by '{}'", form.getName(), owner);
    }

    // ── Status (Publish / Unpublish) ──────────────────────────────────────────

    @Transactional
    public FormEntity publishForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForAction(id, owner, isAdmin);
        form.setStatus(FormEntity.FormStatus.PUBLISHED);
        FormEntity saved = formRepo.save(form);
        log.info("Form '{}' published by '{}'", form.getName(), owner);
        return saved;
    }

    @Transactional
    public FormEntity unpublishForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForAction(id, owner, isAdmin);
        form.setStatus(FormEntity.FormStatus.DRAFT);
        FormEntity saved = formRepo.save(form);
        log.info("Form '{}' unpublished by '{}'", form.getName(), owner);
        return saved;
    }

    // ── Shared Options CRUD ───────────────────────────────────────────────────

    /**
     * Create a new shared_options row. Called when admin saves a new dropdown/radio
     * field.
     */
    @Transactional
    public SharedOptionsEntity createSharedOptions(String optionsJson) {
        SharedOptionsEntity shared = SharedOptionsEntity.builder()
                .optionsJson(optionsJson)
                .build();
        SharedOptionsEntity saved = sharedOptionsRepo.save(shared);
        log.info("Created shared_options row id={}", saved.getId());
        return saved;
    }

    public Optional<SharedOptionsEntity> getSharedOptions(UUID id) {
        return sharedOptionsRepo.findById(id);
    }

    /**
     * Update options_json on a shared_options row.
     * Because form_fields stores NO options_json, all fields that reference this
     * shared_options row automatically see the new options at render/validation
     * time.
     */
    @Transactional
    public Optional<SharedOptionsEntity> updateSharedOptions(UUID id, String optionsJson) {
        return sharedOptionsRepo.findById(id).map(shared -> {
            shared.setOptionsJson(optionsJson);
            SharedOptionsEntity saved = sharedOptionsRepo.save(shared);
            log.info("Updated shared_options id={} — {} field(s) will see new options live",
                    id, fieldRepo.findBySharedOptionsId(id).size());
            return saved;
        });
    }

    // ── Static Field helpers ──────────────────────────────────────────────────

    /** Returns all static fields for a form, ordered by field_order */
    public List<StaticFormFieldEntity> getStaticFields(UUID formId) {
        return staticRepo.findByFormIdOrderByFieldOrderAsc(formId);
    }

    private void saveStaticFields(UUID formId, List<FormDTO.StaticFieldDTO> staticDTOs) {
        if (staticDTOs == null || staticDTOs.isEmpty())
            return;
        for (FormDTO.StaticFieldDTO sf : staticDTOs) {
            staticRepo.save(StaticFormFieldEntity.builder()
                    .id(sf.getId() != null ? sf.getId() : UUID.randomUUID())
                    .formId(formId)
                    .fieldType(sf.getFieldType())
                    .data(sf.getData())
                    .fieldOrder(sf.getFieldOrder())
                    .build());
        }
    }

    /** Returns all groups for a form, ordered by group_order */
    public List<FormGroupEntity> getGroups(UUID formId) {
        return groupRepo.findByFormIdOrderByGroupOrderAsc(formId);
    }

    private void saveGroups(UUID formId, List<FormDTO.GroupDTO> groupDTOs) {
        if (groupDTOs == null || groupDTOs.isEmpty())
            return;
        for (FormDTO.GroupDTO g : groupDTOs) {
            groupRepo.save(FormGroupEntity.builder()
                    .id(g.getId() != null ? g.getId() : UUID.randomUUID())
                    .formId(formId)
                    .groupTitle(g.getGroupTitle())
                    .groupDescription(g.getGroupDescription())
                    .groupOrder(g.getGroupOrder())
                    .rulesJson(g.getRulesJson())
                    .build());
        }
    }

    // ── Helper ────────────────────────────────────────────────────────────────

    private FormFieldEntity toFieldEntity(FormFieldDTO dto, FormEntity parent) {
        return FormFieldEntity.builder()
                .id(dto.getId() != null ? dto.getId() : UUID.randomUUID())
                .form(parent)
                .fieldKey(dto.getFieldKey())
                .label(dto.getLabel())
                .fieldType(dto.getFieldType())
                .required(dto.isRequired())
                .defaultValue(dto.getDefaultValue())
                .validationRegex(dto.getValidationRegex())
                .validationJson(dto.getValidationJson())
                .rulesJson(dto.getRulesJson())
                .uiConfigJson(dto.getUiConfigJson())
                .sharedOptionsId(dto.getSharedOptionsId())
                .fieldOrder(dto.getFieldOrder())
                .disabled(dto.isDisabled())
                .readOnly(dto.isReadOnly())
                // Calculated fields
                .isCalculated(dto.getIsCalculated())
                .formulaExpression(dto.getFormulaExpression())
                .dependenciesJson(serializeDependencies(dto.getDependencies()))
                .precision(dto.getPrecision())
                .lockAfterCalculation(dto.getLockAfterCalculation())
                .parentGroupKey(dto.getParentGroupKey())
                .groupId(dto.getGroupId())
                .build();
    }

    private String serializeDependencies(List<String> deps) {
        if (deps == null || deps.isEmpty())
            return null;
        try {
            return new com.fasterxml.jackson.databind.ObjectMapper().writeValueAsString(deps);
        } catch (Exception e) {
            return null;
        }
    }

    private void validateUniqueFieldKeys(List<FormFieldDTO> fields) {
        if (fields == null || fields.isEmpty())
            return;
        Set<String> seenKeys = new HashSet<>();
        List<String> duplicates = new ArrayList<>();
        for (FormFieldDTO field : fields) {
            String key = field.getFieldKey();
            if (key != null && !key.isEmpty() && !seenKeys.add(key)) {
                duplicates.add(key);
            }
        }
        if (!duplicates.isEmpty()) {
            throw new IllegalArgumentException(
                    "Duplicate field keys found: " + String.join(", ", duplicates) +
                            ". Each field must have a unique key.");
        }
    }

    /** Safely parse visibility string to enum. Returns PUBLIC if null/invalid. */
    private FormEntity.FormVisibility parseVisibility(String visibility) {
        if (visibility == null || visibility.isBlank()) {
            return FormEntity.FormVisibility.PUBLIC;
        }
        try {
            return FormEntity.FormVisibility.valueOf(visibility.trim().toUpperCase());
        } catch (IllegalArgumentException e) {
            return FormEntity.FormVisibility.PUBLIC;
        }
    }
}

package com.formbuilder.service;

import com.formbuilder.dto.FormDTO;
import com.formbuilder.dto.FormFieldDTO;
import com.formbuilder.entity.FormEntity;
import com.formbuilder.entity.FormFieldEntity;
import com.formbuilder.entity.FormGroupEntity;
import com.formbuilder.entity.SharedOptionsEntity;
import com.formbuilder.entity.StaticFormFieldEntity;
import com.formbuilder.repository.FormFieldJpaRepository;
import com.formbuilder.repository.FormGroupRepository;
import com.formbuilder.repository.FormJpaRepository;
import com.formbuilder.repository.SharedOptionsRepository;
import com.formbuilder.repository.StaticFormFieldRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class FormService {

    private final FormJpaRepository formRepo;
    private final FormFieldJpaRepository fieldRepo;
    private final SharedOptionsRepository sharedOptionsRepo;
    private final StaticFormFieldRepository staticRepo;
    private final FormGroupRepository groupRepo;
    private final DynamicTableService dynamicTable;

    // ── Read ──────────────────────────────────────────────────────────────────

    /** Returns only forms owned by the given user (legacy — kept for backward compatibility). */
    public List<FormEntity> getAllForms(String owner) {
        return formRepo.findAllByCreatedByOrderByCreatedAtDesc(owner);
    }

    /**
     * Returns forms visible to the user based on their RBAC roles.
     *
     * Role visibility matrix:
     * - Admin:              ALL non-deleted forms
     * - Role Administrator: ALL non-deleted forms (draft + published), preview-only
     * - Builder:            ONLY their own forms (any status) — not other builders' forms
     * - Others:             PUBLISHED forms filtered by allowed_roles
     *
     * allowed_roles filtering:
     *   If form.allowed_roles is NULL/empty → visible to everyone (default/PUBLIC)
     *   If form.allowed_roles is set → only users with a matching role can see it
     *   Admin & Role Administrator always bypass allowed_roles
     */
    public List<FormEntity> getFormsForRole(String username, Set<String> roleNames) {
        // Admin sees everything
        if (roleNames.contains("Admin")) {
            return formRepo.findAllByOrderByCreatedAtDesc();
        }

        // Role Administrator sees all active forms (including drafts)
        if (roleNames.contains("Role Administrator")) {
            return formRepo.findAllByOrderByCreatedAtDesc();
        }

        // Builder sees ONLY their own forms (any status) — not other builders' forms
        if (roleNames.contains("Builder")) {
            return formRepo.findAllByCreatedByOrderByCreatedAtDesc(username);
        }

        // All other roles: get published forms, then filter by allowed_roles
        List<FormEntity> published = formRepo.findPublishedAccessibleForms();
        return filterByAllowedRoles(published, roleNames);
    }

    /**
     * Filters a list of forms by the allowed_roles JSON column.
     * If allowed_roles is null/empty → form is visible to everyone.
     * If allowed_roles contains role names → user must have at least one matching role.
     */
    private List<FormEntity> filterByAllowedRoles(List<FormEntity> forms, Set<String> userRoles) {
        return forms.stream().filter(form -> {
            String json = form.getAllowedRoles();
            if (json == null || json.isBlank() || json.equals("[]")) {
                return true; // no restriction → visible to all
            }
            List<String> allowed = deserializeRoleList(json);
            if (allowed.isEmpty()) return true;
            // User must have at least one of the allowed roles
            return allowed.stream().anyMatch(userRoles::contains);
        }).collect(Collectors.toList());
    }

    /** Deserialize JSON array string to List<String>. */
    private List<String> deserializeRoleList(String json) {
        if (json == null || json.isBlank()) return List.of();
        try {
            return new com.fasterxml.jackson.databind.ObjectMapper()
                    .readValue(json, new com.fasterxml.jackson.core.type.TypeReference<List<String>>() {});
        } catch (Exception e) {
            log.warn("Failed to parse allowed_roles JSON: {}", json);
            return List.of();
        }
    }

    /** Serialize List<String> to JSON array string. */
    private String serializeRoleList(List<String> roles) {
        if (roles == null || roles.isEmpty()) return null;
        try {
            return new com.fasterxml.jackson.databind.ObjectMapper().writeValueAsString(roles);
        } catch (Exception e) {
            return null;
        }
    }

    /**
     * Returns a form by ID — any owner (used by public endpoints like
     * submit/render).
     */
    public FormEntity getFormById(UUID id) {
        return formRepo.findByIdWithFields(id)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    /**
     * Returns a form by ID scoped to the authenticated owner.
     * Throws NoSuchElementException (→ 404) if form doesn't exist OR belongs to
     * someone else.
     */
    public FormEntity getOwnedFormById(UUID id, String owner) {
        return formRepo.findByIdAndCreatedBy(id, owner)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    /**
     * Returns a form by ID — allows access if the user is the owner OR has Admin role.
     * Used by edit, delete, publish, unpublish, render/admin endpoints.
     */
    public FormEntity getFormForAction(UUID id, String username, boolean isAdmin) {
        if (isAdmin) {
            return formRepo.findByIdWithFields(id)
                    .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
        }
        return formRepo.findByIdAndCreatedBy(id, username)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    /**
     * Returns a form by ID (including soft-deleted) — allows access if owner OR Admin.
     * Used by restore and permanent-delete.
     */
    public FormEntity getFormForActionIncludingTrashed(UUID id, String username, boolean isAdmin) {
        if (isAdmin) {
            return formRepo.findById(id)
                    .map(f -> {
                        // Force-load fields for consistency
                        f.getFields().size();
                        return f;
                    })
                    .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
        }
        return formRepo.findByIdAndCreatedByIncludingTrashed(id, username)
                .orElseThrow(() -> new NoSuchElementException("Form not found: " + id));
    }

    // ── Create ────────────────────────────────────────────────────────────────

    @Transactional
    public FormEntity createForm(FormDTO dto, String owner) {
        validateUniqueFieldKeys(dto.getFields());
        String tableName = dynamicTable.generateTableName(dto.getName());

        FormEntity form = FormEntity.builder()
                .name(dto.getName())
                .description(dto.getDescription())
                .tableName(tableName)
                .createdBy(owner)
                .visibility(parseVisibility(dto.getVisibility()))
                .allowedRoles(serializeRoleList(dto.getAllowedRoles()))
                .allowMultipleSubmissions(
                        dto.getAllowMultipleSubmissions() == null ? true : dto.getAllowMultipleSubmissions())
                .showTimestamp(true) // always compulsory — timestamp every submission
                .expiresAt(dto.getExpiresAt())
                .fields(new ArrayList<>())
                .build();

        // 1. Initial save of form metadata (to get form.id)
        FormEntity saved = formRepo.save(form);

        // 2. Save static fields (no FK dependencies)
        saveStaticFields(saved.getId(), dto.getStaticFields());

        // 3. Save groups (must exist before dynamic fields reference them)
        saveGroups(saved.getId(), dto.getGroups());
        groupRepo.flush(); // Force groups to DB before saving fields

        // 4. Map and save dynamic fields
        if (dto.getFields() != null) {
            for (FormFieldDTO f : dto.getFields()) {
                saved.getFields().add(toFieldEntity(f, saved));
            }
            // Save again to flush fields with correct IDs
            saved = formRepo.save(saved);
        }

        dynamicTable.createTable(tableName, saved.getFields());

        log.info("Form '{}' created by '{}' with table '{}'", saved.getName(), owner, tableName);
        return saved;
    }

    // ── Update ────────────────────────────────────────────────────────────────

    @Transactional
    public FormEntity updateForm(UUID id, FormDTO dto, String owner, boolean isAdmin) {
        validateUniqueFieldKeys(dto.getFields());

        FormEntity existing = getFormForAction(id, owner, isAdmin);

        Map<String, FormFieldEntity> oldByKey = existing.getFields().stream()
                .collect(Collectors.toMap(FormFieldEntity::getFieldKey, f -> f));

        Set<String> newKeys = dto.getFields() != null
                ? dto.getFields().stream().map(FormFieldDTO::getFieldKey).collect(Collectors.toSet())
                : Set.of();

        // DDL: add / alter columns
        if (dto.getFields() != null) {
            for (FormFieldDTO f : dto.getFields()) {
                if (!oldByKey.containsKey(f.getFieldKey())) {
                    dynamicTable.addColumn(existing.getTableName(), f.getFieldKey(), f.getFieldType());
                } else {
                    String oldType = oldByKey.get(f.getFieldKey()).getFieldType();
                    if (!oldType.equals(f.getFieldType())) {
                        dynamicTable.alterColumnType(existing.getTableName(), f.getFieldKey(), f.getFieldType());
                    }
                }
            }
        }
        // DDL: drop removed columns
        for (String key : oldByKey.keySet()) {
            if (!newKeys.contains(key)) {
                dynamicTable.dropColumn(existing.getTableName(), key);
            }
        }

        // 1. Replace all static fields
        staticRepo.deleteByFormId(existing.getId());
        saveStaticFields(existing.getId(), dto.getStaticFields());

        // 2. Replace all groups (must exist before fields reference them)
        groupRepo.deleteByFormId(existing.getId());
        groupRepo.flush(); // Force delete to DB
        saveGroups(existing.getId(), dto.getGroups());
        groupRepo.flush(); // Force inserts to DB

        // 3. Update form metadata and fields
        existing.setName(dto.getName());
        existing.setDescription(dto.getDescription());
        if (dto.getVisibility() != null) {
            existing.setVisibility(parseVisibility(dto.getVisibility()));
        }
        if (dto.getAllowedRoles() != null) {
            existing.setAllowedRoles(serializeRoleList(dto.getAllowedRoles()));
        }
        if (dto.getAllowMultipleSubmissions() != null)
            existing.setAllowMultipleSubmissions(dto.getAllowMultipleSubmissions());
        existing.setExpiresAt(dto.getExpiresAt());
        existing.getFields().removeIf(field -> !newKeys.contains(field.getFieldKey()));

        if (dto.getFields() != null) {
            for (FormFieldDTO dtoField : dto.getFields()) {
                FormFieldEntity existingField = oldByKey.get(dtoField.getFieldKey());
                if (existingField != null) {
                    existingField.setLabel(dtoField.getLabel());
                    existingField.setFieldType(dtoField.getFieldType());
                    existingField.setRequired(dtoField.isRequired());
                    existingField.setDefaultValue(dtoField.getDefaultValue());
                    existingField.setValidationRegex(dtoField.getValidationRegex());
                    existingField.setValidationJson(dtoField.getValidationJson());
                    existingField.setRulesJson(dtoField.getRulesJson());
                    existingField.setUiConfigJson(dtoField.getUiConfigJson());
                    existingField.setSharedOptionsId(dtoField.getSharedOptionsId());
                    existingField.setFieldOrder(dtoField.getFieldOrder());
                    existingField.setDisabled(dtoField.isDisabled());
                    existingField.setReadOnly(dtoField.isReadOnly());
                    existingField.setIsCalculated(dtoField.getIsCalculated());
                    existingField.setFormulaExpression(dtoField.getFormulaExpression());
                    existingField.setDependenciesJson(serializeDependencies(dtoField.getDependencies()));
                    existingField.setPrecision(dtoField.getPrecision());
                    existingField.setLockAfterCalculation(dtoField.getLockAfterCalculation());
                    existingField.setParentGroupKey(dtoField.getParentGroupKey());
                    existingField.setGroupId(dtoField.getGroupId());
                } else {
                    existing.getFields().add(toFieldEntity(dtoField, existing));
                }
            }
        }

        return formRepo.save(existing);
    }

    // ── Delete / Soft Delete / Trash ────────────────────────────────────────────

    /**
     * Soft-delete: mark the form as deleted without removing data.
     * The form disappears from all active listings and appears in the trash.
     */
    @Transactional
    public void deleteForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForAction(id, owner, isAdmin);
        form.setSoftDeleted(true);
        form.setDeletedAt(java.time.LocalDateTime.now());
        formRepo.save(form);
        log.info("Form '{}' soft-deleted by '{}'", form.getName(), owner);
    }

    /** Returns soft-deleted forms — Admin sees all, others see only their own. */
    public List<FormEntity> getTrashForms(String owner, boolean isAdmin) {
        if (isAdmin) {
            return formRepo.findAllTrashed();
        }
        return formRepo.findTrashedByOwner(owner);
    }

    /** Restore a soft-deleted form back to active. */
    @Transactional
    public FormEntity restoreForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForActionIncludingTrashed(id, owner, isAdmin);
        form.setSoftDeleted(false);
        form.setDeletedAt(null);
        FormEntity saved = formRepo.save(form);
        log.info("Form '{}' restored by '{}'", form.getName(), owner);
        return saved;
    }

    /** Permanently delete a soft-deleted form and drop its submission table. */
    @Transactional
    public void permanentDeleteForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForActionIncludingTrashed(id, owner, isAdmin);
        if (!form.isSoftDeleted()) {
            throw new IllegalStateException("Form must be in trash before permanent deletion");
        }
        dynamicTable.dropTable(form.getTableName());
        formRepo.delete(form);
        log.info("Form '{}' permanently deleted by '{}'", form.getName(), owner);
    }

    // ── Status (Publish / Unpublish) ──────────────────────────────────────────

    @Transactional
    public FormEntity publishForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForAction(id, owner, isAdmin);
        form.setStatus(FormEntity.FormStatus.PUBLISHED);
        FormEntity saved = formRepo.save(form);
        log.info("Form '{}' published by '{}'", form.getName(), owner);
        return saved;
    }

    @Transactional
    public FormEntity unpublishForm(UUID id, String owner, boolean isAdmin) {
        FormEntity form = getFormForAction(id, owner, isAdmin);
        form.setStatus(FormEntity.FormStatus.DRAFT);
        FormEntity saved = formRepo.save(form);
        log.info("Form '{}' unpublished by '{}'", form.getName(), owner);
        return saved;
    }

    // ── Shared Options CRUD ───────────────────────────────────────────────────

    /**
     * Create a new shared_options row. Called when admin saves a new dropdown/radio
     * field.
     */
    @Transactional
    public SharedOptionsEntity createSharedOptions(String optionsJson) {
        SharedOptionsEntity shared = SharedOptionsEntity.builder()
                .optionsJson(optionsJson)
                .build();
        SharedOptionsEntity saved = sharedOptionsRepo.save(shared);
        log.info("Created shared_options row id={}", saved.getId());
        return saved;
    }

    public Optional<SharedOptionsEntity> getSharedOptions(UUID id) {
        return sharedOptionsRepo.findById(id);
    }

    /**
     * Update options_json on a shared_options row.
     * Because form_fields stores NO options_json, all fields that reference this
     * shared_options row automatically see the new options at render/validation
     * time.
     */
    @Transactional
    public Optional<SharedOptionsEntity> updateSharedOptions(UUID id, String optionsJson) {
        return sharedOptionsRepo.findById(id).map(shared -> {
            shared.setOptionsJson(optionsJson);
            SharedOptionsEntity saved = sharedOptionsRepo.save(shared);
            log.info("Updated shared_options id={} — {} field(s) will see new options live",
                    id, fieldRepo.findBySharedOptionsId(id).size());
            return saved;
        });
    }

    // ── Static Field helpers ──────────────────────────────────────────────────

    /** Returns all static fields for a form, ordered by field_order */
    public List<StaticFormFieldEntity> getStaticFields(UUID formId) {
        return staticRepo.findByFormIdOrderByFieldOrderAsc(formId);
    }

    private void saveStaticFields(UUID formId, List<FormDTO.StaticFieldDTO> staticDTOs) {
        if (staticDTOs == null || staticDTOs.isEmpty())
            return;
        for (FormDTO.StaticFieldDTO sf : staticDTOs) {
            staticRepo.save(StaticFormFieldEntity.builder()
                    .id(sf.getId() != null ? sf.getId() : UUID.randomUUID())
                    .formId(formId)
                    .fieldType(sf.getFieldType())
                    .data(sf.getData())
                    .fieldOrder(sf.getFieldOrder())
                    .build());
        }
    }

    /** Returns all groups for a form, ordered by group_order */
    public List<FormGroupEntity> getGroups(UUID formId) {
        return groupRepo.findByFormIdOrderByGroupOrderAsc(formId);
    }

    private void saveGroups(UUID formId, List<FormDTO.GroupDTO> groupDTOs) {
        if (groupDTOs == null || groupDTOs.isEmpty())
            return;
        for (FormDTO.GroupDTO g : groupDTOs) {
            groupRepo.save(FormGroupEntity.builder()
                    .id(g.getId() != null ? g.getId() : UUID.randomUUID())
                    .formId(formId)
                    .groupTitle(g.getGroupTitle())
                    .groupDescription(g.getGroupDescription())
                    .groupOrder(g.getGroupOrder())
                    .rulesJson(g.getRulesJson())
                    .build());
        }
    }

    // ── Helper ────────────────────────────────────────────────────────────────

    private FormFieldEntity toFieldEntity(FormFieldDTO dto, FormEntity parent) {
        return FormFieldEntity.builder()
                .id(dto.getId() != null ? dto.getId() : UUID.randomUUID())
                .form(parent)
                .fieldKey(dto.getFieldKey())
                .label(dto.getLabel())
                .fieldType(dto.getFieldType())
                .required(dto.isRequired())
                .defaultValue(dto.getDefaultValue())
                .validationRegex(dto.getValidationRegex())
                .validationJson(dto.getValidationJson())
                .rulesJson(dto.getRulesJson())
                .uiConfigJson(dto.getUiConfigJson())
                .sharedOptionsId(dto.getSharedOptionsId())
                .fieldOrder(dto.getFieldOrder())
                .disabled(dto.isDisabled())
                .readOnly(dto.isReadOnly())
                // Calculated fields
                .isCalculated(dto.getIsCalculated())
                .formulaExpression(dto.getFormulaExpression())
                .dependenciesJson(serializeDependencies(dto.getDependencies()))
                .precision(dto.getPrecision())
                .lockAfterCalculation(dto.getLockAfterCalculation())
                .parentGroupKey(dto.getParentGroupKey())
                .groupId(dto.getGroupId())
                .build();
    }

    private String serializeDependencies(List<String> deps) {
        if (deps == null || deps.isEmpty())
            return null;
        try {
            return new com.fasterxml.jackson.databind.ObjectMapper().writeValueAsString(deps);
        } catch (Exception e) {
            return null;
        }
    }

    private void validateUniqueFieldKeys(List<FormFieldDTO> fields) {
        if (fields == null || fields.isEmpty())
            return;
        Set<String> seenKeys = new HashSet<>();
        List<String> duplicates = new ArrayList<>();
        for (FormFieldDTO field : fields) {
            String key = field.getFieldKey();
            if (key != null && !key.isEmpty() && !seenKeys.add(key)) {
                duplicates.add(key);
            }
        }
        if (!duplicates.isEmpty()) {
            throw new IllegalArgumentException(
                    "Duplicate field keys found: " + String.join(", ", duplicates) +
                            ". Each field must have a unique key.");
        }
    }

    /** Safely parse visibility string to enum. Returns PUBLIC if null/invalid. */
    private FormEntity.FormVisibility parseVisibility(String visibility) {
        if (visibility == null || visibility.isBlank()) {
            return FormEntity.FormVisibility.PUBLIC;
        }
        try {
            return FormEntity.FormVisibility.valueOf(visibility.trim().toUpperCase());
        } catch (IllegalArgumentException e) {
            return FormEntity.FormVisibility.PUBLIC;
        }
    }
}

import { useRouter } from 'next/router';
import Link from 'next/link';
import { logout } from '../services/api';
import { toastSuccess, toastError } from '../services/toast';
import { useTheme } from '../context/ThemeContext';
import { useAuth } from '../context/AuthContext';


export default function Navbar() {
    const router = useRouter();
    const { theme, toggleTheme } = useTheme();
    const { can, clearAuth, user, roles } = useAuth();

    const handleLogout = async () => {
        try {
            await logout();
            clearAuth();
            toastSuccess('You have been logged out.');
            router.push('/login');
        } catch {
            toastError('Logout failed. Please try again.');
        }
    };

    // Display the highest-priority role name
    const roleDisplay = roles && roles.length > 0
        ? roles.map(r => r.roleName).join(', ')
        : 'Viewer';

    return (
        <nav className="navbar">
            <Link href="/dashboard" className="navbar-brand">
                ⚡ FormCraft
            </Link>
            <div className="navbar-actions">
                {user && (
                    <span style={{
                        fontSize: 11, color: 'var(--text-muted)',
                        padding: '4px 10px', borderRadius: 8,
                        background: 'rgba(255,255,255,0.05)',
                        border: '1px solid rgba(255,255,255,0.08)',
                        display: 'flex', alignItems: 'center', gap: 6,
                        whiteSpace: 'nowrap'
                    }}>
                         {user.username} <span style={{ opacity: 0.5 }}>|</span> {roleDisplay}
                    </span>
                )}

                <Link href="/dashboard" className="btn btn-secondary btn-sm">
                    Dashboard
                </Link>

                {can('MANAGE') && (
                    <Link href="/roles" className="btn btn-secondary btn-sm">
                        ️ Roles
                    </Link>
                )}

                {can('MANAGE') && (
                    <Link href="/users" className="btn btn-secondary btn-sm">
                         Users
                    </Link>
                )}

                {can('WRITE') && (
                    <Link href="/builder/new" className="btn btn-primary btn-sm">
                        + New Form
                    </Link>
                )}

                <button
                    className="theme-toggle-btn"
                    onClick={(e) => toggleTheme(e)}
                    title={theme === 'dark' ? 'Switch to Light mode' : 'Switch to Dark mode'}
                    aria-label="Toggle theme"
                >
                    <span className={`theme-toggle-icon ${theme === 'dark' ? 'icon-sun' : 'icon-moon'}`}>
                        {theme === 'dark' ? '☀️' : ''}
                    </span>
                </button>
                <button className="btn btn-secondary btn-sm" onClick={handleLogout}>
                    Logout
                </button>
            </div>
        </nav>
    );
}

