                                            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginTop: 8 }}>
                                                {availableRoles.map(role => {
                                                    const checked = allowedRoles.includes(role.roleName);
                                                    return (
                                                        <label key={role.id}
                                                            style={{
                                                                display: 'flex', alignItems: 'center', gap: 6,
                                                                padding: '5px 12px', borderRadius: 6, fontSize: 13,
                                                                cursor: 'pointer', userSelect: 'none',
                                                                background: checked ? 'var(--primary-light, #e8f0fe)' : 'var(--bg-card)',
                                                                border: `1.5px solid ${checked ? 'var(--primary, #4285f4)' : 'var(--border)'}`,
                                                                color: checked ? 'var(--primary, #4285f4)' : 'var(--text-secondary)',
                                                                fontWeight: checked ? 600 : 400,
                                                                transition: 'all .15s ease',
                                                            }}>
                                                            <input type="checkbox" checked={checked}
                                                                style={{ display: 'none' }}
                                                                onChange={() => {
                                                                    setAllowedRoles(prev =>
                                                                        prev.includes(role.roleName)
                                                                            ? prev.filter(r => r !== role.roleName)
                                                                            : [...prev, role.roleName]
                                                                    );
                                                                }} />
                                                            <span>{checked ? '☑' : '☐'}</span>
                                                            {role.roleName}
                                                        </label>
                                                    );
                                                })}
                                            </div>
                                            {availableRoles.length > 0 && (
                                                <div style={{ marginTop: 6, display: 'flex', gap: 10, fontSize: 11 }}>
                                                    <button type="button" className="btn btn-secondary btn-sm" style={{ fontSize: 11, padding: '2px 8px' }}
                                                        onClick={() => setAllowedRoles(availableRoles.map(r => r.roleName))}>
                                                        Select All
                                                    </button>
                                                    <button type="button" className="btn btn-secondary btn-sm" style={{ fontSize: 11, padding: '2px 8px' }}
                                                        onClick={() => setAllowedRoles([])}>
                                                        Clear All
                                                    </button>
                                                    <span style={{ color: 'var(--text-muted)', alignSelf: 'center' }}>
                                                         Admin & Role Admin always have access
                                                    </span>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </>
                            )}
                        </div>

                        {/* Preview (navigates to /preview/:id — only after save) */}
                        <Link href="/dashboard" className="btn btn-secondary btn-sm">
                            ← Cancel
                        </Link>

                        <button
                            id="save-form-btn"
                            className="btn btn-primary btn-sm"
                            onClick={handleSave}
                            disabled={saving || !formName.trim()}
                        >
                            {saving ? (
                                <><span className="spinner" style={{ width: 14, height: 14 }} /> Saving…</>
                            ) : (
                                ' Save Form'
                            )}
                        </button>
                    </div>
                </header>

                {/* ── Left Palette ─────────────────────────────────────── */}
                <FieldPalette />

                {/* ── Canvas ───────────────────────────────────────────── */}
                <main className="builder-canvas-wrap">
                    <Canvas fields={fields} setFields={setFields} groups={groups} setGroups={setGroups} />
                </main>
            </div>
        </>
    );
}

import { useEffect, useState } from 'react';
import Head from 'next/head';
import { useRouter } from 'next/router';
import Navbar from '../../components/Navbar';
import { getAdminLogs } from '../../services/api';
import { toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

const ACTIONS = [
    'CREATE_FORM', 'UPDATE_FORM', 'DELETE_FORM', 'PUBLISH_FORM', 'UNPUBLISH_FORM', 'SUBMIT_FORM',
    'CREATE_ROLE', 'UPDATE_ROLE', 'DELETE_ROLE', 'ASSIGN_ROLE', 'REMOVE_ROLE', 'UPDATE_PERMISSION'
];

export default function AdminLogsPage() {
    const router = useRouter();
    const { user, hasRole, loading: authLoading } = useAuth();

    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filters, setFilters] = useState({
        action: '',
        user: '',
        fromDate: '',
        toDate: '',
    });

    useEffect(() => {
        if (authLoading) return;
        if (!user) {
            router.replace('/login');
            return;
        }
        if (!hasRole('Admin')) {
            router.replace('/dashboard');
            return;
        }
        loadLogs(filters);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [authLoading, user]);

    async function loadLogs(currentFilters) {
        setLoading(true);
        try {
            const data = await getAdminLogs(currentFilters);
            setRows(Array.isArray(data) ? data : []);
        } catch (err) {
            toastError(err.message || 'Failed to load admin logs.');
        } finally {
            setLoading(false);
        }
    }

    function applyFilters(e) {
        e.preventDefault();
        loadLogs(filters);
    }

    function clearFilters() {
        const next = { action: '', user: '', fromDate: '', toDate: '' };
        setFilters(next);
        loadLogs(next);
    }

    return (
        <>
            <Head>
                <title>Admin Logs - FormCraft</title>
            </Head>
            <Navbar />

            <div className="users-page">
                <div className="users-page-header">
                    <div>
                        <h1>Admin Logs</h1>
                        <p>Complete audit trail of important system actions.</p>
                    </div>
                </div>

                <form onSubmit={applyFilters} className="user-form-card" style={{ marginBottom: 16 }}>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, minmax(140px, 1fr))', gap: 10 }}>
                        <select
                            className="form-input"
                            value={filters.action}
                            onChange={(e) => setFilters((p) => ({ ...p, action: e.target.value }))}
                        >
                            <option value="">All Actions</option>
                            {ACTIONS.map((a) => <option key={a} value={a}>{a}</option>)}
                        </select>

                        <input
                            className="form-input"
                            placeholder="Filter by user"
                            value={filters.user}
                            onChange={(e) => setFilters((p) => ({ ...p, user: e.target.value }))}
                        />

                        <input
                            type="date"
                            className="form-input"
                            value={filters.fromDate}
                            onChange={(e) => setFilters((p) => ({ ...p, fromDate: e.target.value }))}
                        />

                        <input
                            type="date"
                            className="form-input"
                            value={filters.toDate}
                            onChange={(e) => setFilters((p) => ({ ...p, toDate: e.target.value }))}
                        />
                    </div>

                    <div style={{ marginTop: 10, display: 'flex', gap: 8 }}>
                        <button type="submit" className="btn btn-primary btn-sm">Apply</button>
                        <button type="button" className="btn btn-secondary btn-sm" onClick={clearFilters}>Clear</button>
                    </div>
                </form>

                <div className="users-table-wrap">
                    <table className="users-table">
                        <thead>
                            <tr>
                                <th>Timestamp</th>
                                <th>User</th>
                                <th>Action</th>
                                <th>Target</th>
                                <th>Description</th>
                            </tr>
                        </thead>
                        <tbody>
                            {loading ? (
                                <tr><td colSpan={5}>Loading logs...</td></tr>
                            ) : rows.length === 0 ? (
                                <tr><td colSpan={5}>No logs found.</td></tr>
                            ) : rows.map((r) => (
                                <tr key={r.id}>
                                    <td>{r.created_at ? new Date(r.created_at).toLocaleString() : '-'}</td>
                                    <td>{r.performed_by_username || '-'}</td>
                                    <td><span className="perm-tag">{r.action}</span></td>
                                    <td>{r.target_entity}{r.target_entity_id ? `:${r.target_entity_id}` : ''}</td>
                                    <td>{r.description}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </>
    );
}

import { useEffect, useState } from 'react';
import Head from 'next/head';
import { useRouter } from 'next/router';
import Navbar from '../../components/Navbar';
import { getRoleAssignmentLogs, getRoles } from '../../services/api';
import { toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

export default function RoleAssignmentLogsPage() {
    const router = useRouter();
    const { user, hasRole, loading: authLoading } = useAuth();

    const [rows, setRows] = useState([]);
    const [roles, setRoles] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filters, setFilters] = useState({
        roleId: '',
        user: '',
        fromDate: '',
        toDate: '',
    });

    useEffect(() => {
        if (authLoading) return;
        if (!user) {
            router.replace('/login');
            return;
        }
        const allowed = hasRole('Role Administrator') || hasRole('Admin');
        if (!allowed) {
            router.replace('/dashboard');
            return;
        }

        loadRoles();
        loadLogs(filters);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [authLoading, user]);

    async function loadRoles() {
        try {
            const data = await getRoles();
            setRoles(Array.isArray(data) ? data : []);
        } catch {
            setRoles([]);
        }
    }

    async function loadLogs(currentFilters) {
        setLoading(true);
        try {
            const data = await getRoleAssignmentLogs(currentFilters);
            setRows(Array.isArray(data) ? data : []);
        } catch (err) {
            toastError(err.message || 'Failed to load role logs.');
        } finally {
            setLoading(false);
        }
    }

    function applyFilters(e) {
        e.preventDefault();
        loadLogs(filters);
    }

    function clearFilters() {
        const next = { roleId: '', user: '', fromDate: '', toDate: '' };
        setFilters(next);
        loadLogs(next);
    }

    return (
        <>
            <Head>
                <title>Role Assignment Logs - FormCraft</title>
            </Head>
            <Navbar />

            <div className="users-page">
                <div className="users-page-header">
                    <div>
                        <h1>Role Assignment Logs</h1>
                        <p>Track role assignment and permission update activity.</p>
                    </div>
                </div>

                <form onSubmit={applyFilters} className="user-form-card" style={{ marginBottom: 16 }}>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, minmax(140px, 1fr))', gap: 10 }}>
                        <select
                            className="form-input"
                            value={filters.roleId}
                            onChange={(e) => setFilters((p) => ({ ...p, roleId: e.target.value }))}
                        >
                            <option value="">All Roles</option>
                            {roles.map((r) => (
                                <option key={r.id} value={r.id}>{r.roleName}</option>
                            ))}
                        </select>

                        <input
                            className="form-input"
                            placeholder="Filter by username"
                            value={filters.user}
                            onChange={(e) => setFilters((p) => ({ ...p, user: e.target.value }))}
                        />

                        <input
                            type="date"
                            className="form-input"
                            value={filters.fromDate}
                            onChange={(e) => setFilters((p) => ({ ...p, fromDate: e.target.value }))}
                        />

                        <input
                            type="date"
                            className="form-input"
                            value={filters.toDate}
                            onChange={(e) => setFilters((p) => ({ ...p, toDate: e.target.value }))}
                        />
                    </div>

                    <div style={{ marginTop: 10, display: 'flex', gap: 8 }}>
                        <button type="submit" className="btn btn-primary btn-sm">Apply</button>
                        <button type="button" className="btn btn-secondary btn-sm" onClick={clearFilters}>Clear</button>
                    </div>
                </form>

                <div className="users-table-wrap">
                    <table className="users-table">
                        <thead>
                            <tr>
                                <th>Timestamp</th>
                                <th>Role</th>
                                <th>User</th>
                                <th>Assigned By</th>
                                <th>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {loading ? (
                                <tr><td colSpan={5}>Loading logs...</td></tr>
                            ) : rows.length === 0 ? (
                                <tr><td colSpan={5}>No logs found.</td></tr>
                            ) : rows.map((r) => (
                                <tr key={r.id}>
                                    <td>{r.created_at ? new Date(r.created_at).toLocaleString() : '-'}</td>
                                    <td>{r.related_role_name || (r.related_role_id ? `Role #${r.related_role_id}` : '-')}</td>
                                    <td>{r.related_username || '-'}</td>
                                    <td>{r.performed_by_username || '-'}</td>
                                    <td><span className="perm-tag">{r.action}</span></td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../components/Navbar';
import FormRenderer from '../../components/FormRenderer';
import { getFormRenderAdmin } from '../../services/api';
import { toastError } from '../../services/toast';

/**
 * Form Preview Page — /preview/[id]
 * Admin view — shows the form exactly as end-users will see it.
 * Uses /render/admin so DRAFT forms are also previewable.
 * Submission is DISABLED (isPreview=true) so no data is written.
 */
export default function PreviewPage() {
    const router = useRouter();
    const { id } = router.query;

    const [form, setForm] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!id) return;
        getFormRenderAdmin(id)
            .then((data) => {
                setForm({
                    id: data.formId,
                    name: data.formName,
                    description: data.formDescription,
                    fields: data.fields || [],
                    groups: data.groups || [],
                });
            })
            .catch(() => toastError('Failed to load form.'))
            .finally(() => setLoading(false));
    }, [id]);

    if (loading) {
        return (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', background: 'var(--bg-base)' }}>
                <span className="spinner" style={{ width: 36, height: 36 }} />
            </div>
        );
    }

    return (
        <>
            <Head>
                <title>{form?.name ? `Preview — ${form.name}` : 'Preview — FormCraft'}</title>
            </Head>

            <div className="page">
                <Navbar />

                <div className="form-page">
                    {/* Back + Share nav */}
                    <div className="form-page-nav animate-down">
                        <Link href={`/builder/${id}`} className="btn btn-secondary btn-sm">
                            ← Edit Form
                        </Link>
                        <div style={{ display: 'flex', gap: 10 }}>
                            <span className="badge badge-text" style={{ padding: '6px 14px', fontSize: 12 }}>
                                 Preview Mode
                            </span>
                            <Link href={`/submit/${id}`} className="btn btn-primary btn-sm">
                                Open Submission Link ↗
                            </Link>
                        </div>
                    </div>

                    {form ? (
                        <FormRenderer
                            form={form}
                            isPreview={true}
                            onSubmit={() => Promise.resolve()}  // no-op in preview
                        />
                    ) : (
                        <div className="empty-state">
                            <div className="empty-state-icon">⚠</div>
                            <h3>Form not found</h3>
                            <p>This form may have been deleted.</p>
                        </div>
                    )}
                </div>
            </div>
        </>
    );
}

