import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../components/Navbar';
import { createUser, getRoles, assignRoleToUser } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

export default function CreateUserPage() {
    const router = useRouter();
    const { user, loading: authLoading } = useAuth();
    const [username, setUsername] = useState('');
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [selectedRoles, setSelectedRoles] = useState(new Set());
    const [allRoles, setAllRoles] = useState([]);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (authLoading) return;
        if (!user) { router.replace('/login'); return; }
        loadRoles();
    }, [authLoading, user, router]);

    async function loadRoles() {
        try {
            const data = await getRoles();
            setAllRoles(Array.isArray(data) ? data : []);
        } catch {
            toastError('Failed to load roles.');
        }
    }

    function toggleRole(roleId) {
        setSelectedRoles(prev => {
            const next = new Set(prev);
            if (next.has(roleId)) {
                next.delete(roleId);
            } else {
                next.add(roleId);
            }
            return next;
        });
    }

    async function handleSubmit(e) {
        e.preventDefault();
        setError('');

        if (!username.trim()) {
            setError('Username is required. Must match an existing registered account.');
            return;
        }

        setSaving(true);
        try {
            // Step 1: Create the RBAC user profile
            const createdUser = await createUser(username.trim(), name.trim() || null, email.trim() || null);

            // Step 2: Assign selected roles (one by one — idempotent)
            for (const roleId of selectedRoles) {
                try {
                    await assignRoleToUser(createdUser.id, roleId);
                } catch (err) {
                    console.warn(`Failed to assign role ${roleId}:`, err.message);
                }
            }

            toastSuccess(`User "${name.trim() || username.trim()}" created successfully.`);
            router.push('/users');
        } catch (err) {
            const msg = err.message || 'Failed to create user.';
            setError(msg);
            toastError(msg);
        } finally {
            setSaving(false);
        }
    }

    return (
        <>
            <Head>
                <title>Create User — FormCraft</title>
            </Head>
            <Navbar />

            <div className="users-page">
                <div className="users-page-header">
                    <div>
                        <h1>Create New User</h1>
                        <p>Create an RBAC profile and assign roles</p>
                    </div>
                    <Link href="/users" className="btn btn-secondary">
                        ← Back to Users
                    </Link>
                </div>

                <div className="user-form-card">
                    <form onSubmit={handleSubmit}>
                        {/* Error Banner */}
                        {error && (
                            <div style={{
                                padding: '12px 16px', marginBottom: 20,
                                background: 'rgba(239,68,68,0.1)',
                                border: '1px solid rgba(239,68,68,0.3)',
                                borderRadius: 'var(--radius-sm)',
                                color: '#FCA5A5', fontSize: 14
                            }}>
                                ⚠ {error}
                            </div>
                        )}

                        {/* Username */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="username">
                                Username *
                            </label>
                            <input
                                id="username"
                                type="text"
                                className="form-input"
                                placeholder="Enter a unique username"
                                value={username}
                                onChange={e => setUsername(e.target.value)}
                                autoFocus
                                maxLength={100}
                            />
                            <span style={{ fontSize: 11, color: 'var(--text-muted)' }}>
                                Creates a new user profile. The user will need to register via /register to set their password.
                            </span>
                        </div>

                        {/* Display Name */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="name">
                                Display Name
                            </label>
                            <input
                                id="name"
                                type="text"
                                className="form-input"
                                placeholder="e.g. John Doe"
                                value={name}
                                onChange={e => setName(e.target.value)}
                                maxLength={100}
                            />
                        </div>

                        {/* Email */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="email">
                                Email
                            </label>
                            <input
                                id="email"
                                type="email"
                                className="form-input"
                                placeholder="e.g. john@example.com"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                maxLength={150}
                            />
                        </div>

                        {/* Role Assignment */}
                        {allRoles.length > 0 && (
                            <div className="role-assign-section">
                                <h3>Assign Roles</h3>
                                <span style={{ fontSize: 12, color: 'var(--text-muted)', display: 'block', marginBottom: 12 }}>
                                    {selectedRoles.size} role{selectedRoles.size !== 1 ? 's' : ''} selected
                                </span>
                                <div className="role-assign-grid">
                                    {allRoles.map(role => (
                                        <label
                                            key={role.id}
                                            className={`role-assign-item ${selectedRoles.has(role.id) ? 'assigned' : ''}`}
                                        >
                                            <input
                                                type="checkbox"
                                                checked={selectedRoles.has(role.id)}
                                                onChange={() => toggleRole(role.id)}
                                            />
                                            <div className="role-assign-label">
                                                <span className="role-assign-name">
                                                    {role.isSystemRole ? '' : '⚙️'} {role.roleName}
                                                </span>
                                                <span className="role-assign-type">
                                                    {role.isSystemRole ? 'System' : 'Custom'} · {(role.permissions || []).length} permissions
                                                </span>
                                            </div>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Actions */}
                        <div className="user-form-actions">
                            <button
                                type="submit"
                                className="btn btn-primary"
                                disabled={saving}
                            >
                                {saving ? 'Creating...' : '✓ Create User'}
                            </button>
                            <Link href="/users" className="btn btn-secondary">
                                Cancel
                            </Link>
                        </div>
                    </form>
                </div>
            </div>
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../components/Navbar';
import { createUser, getRoles, assignRoleToUser } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

export default function CreateUserPage() {
    const router = useRouter();
    const { user, loading: authLoading } = useAuth();
    const [username, setUsername] = useState('');
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [selectedRoleId, setSelectedRoleId] = useState(null);
    const [allRoles, setAllRoles] = useState([]);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (authLoading) return;
        if (!user) { router.replace('/login'); return; }
        loadRoles();
    }, [authLoading, user, router]);

    async function loadRoles() {
        try {
            const data = await getRoles();
            setAllRoles(Array.isArray(data) ? data : []);
        } catch {
            toastError('Failed to load roles.');
        }
    }

    async function handleSubmit(e) {
        e.preventDefault();
        setError('');

        if (!username.trim()) {
            setError('Username is required. Must match an existing registered account.');
            return;
        }

        if (!selectedRoleId) {
            setError('Please select one role. A user can have only one role.');
            return;
        }

        setSaving(true);
        try {
            // Step 1: Create the RBAC user profile
            const createdUser = await createUser(username.trim(), name.trim() || null, email.trim() || null);

            // Step 2: Assign exactly one role
            await assignRoleToUser(createdUser.id, selectedRoleId);

            toastSuccess(`User "${name.trim() || username.trim()}" created successfully.`);
            router.push('/users');
        } catch (err) {
            const msg = err.message || 'Failed to create user.';
            setError(msg);
            toastError(msg);
        } finally {
            setSaving(false);
        }
    }

    return (
        <>
            <Head>
                <title>Create User — FormCraft</title>
            </Head>
            <Navbar />

            <div className="users-page">
                <div className="users-page-header">
                    <div>
                        <h1>Create New User</h1>
                        <p>Create an RBAC profile and assign roles</p>
                    </div>
                    <Link href="/users" className="btn btn-secondary">
                        ← Back to Users
                    </Link>
                </div>

                <div className="user-form-card">
                    <form onSubmit={handleSubmit}>
                        {/* Error Banner */}
                        {error && (
                            <div style={{
                                padding: '12px 16px', marginBottom: 20,
                                background: 'rgba(239,68,68,0.1)',
                                border: '1px solid rgba(239,68,68,0.3)',
                                borderRadius: 'var(--radius-sm)',
                                color: '#FCA5A5', fontSize: 14
                            }}>
                                ⚠ {error}
                            </div>
                        )}

                        {/* Username */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="username">
                                Username *
                            </label>
                            <input
                                id="username"
                                type="text"
                                className="form-input"
                                placeholder="Enter a unique username"
                                value={username}
                                onChange={e => setUsername(e.target.value)}
                                autoFocus
                                maxLength={100}
                            />
                            <span style={{ fontSize: 11, color: 'var(--text-muted)' }}>
                                Creates a new user profile. The user will need to register via /register to set their password.
                            </span>
                        </div>

                        {/* Display Name */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="name">
                                Display Name
                            </label>
                            <input
                                id="name"
                                type="text"
                                className="form-input"
                                placeholder="e.g. John Doe"
                                value={name}
                                onChange={e => setName(e.target.value)}
                                maxLength={100}
                            />
                        </div>

                        {/* Email */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="email">
                                Email
                            </label>
                            <input
                                id="email"
                                type="email"
                                className="form-input"
                                placeholder="e.g. john@example.com"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                maxLength={150}
                            />
                        </div>

                        {/* Role Assignment */}
                        {allRoles.length > 0 && (
                            <div className="role-assign-section">
                                <h3>Assign Role</h3>
                                <span style={{ fontSize: 12, color: 'var(--text-muted)', display: 'block', marginBottom: 12 }}>
                                    {selectedRoleId ? '1 role selected' : 'Select exactly one role'}
                                </span>
                                <div className="role-assign-grid">
                                    {allRoles.map(role => (
                                        <label
                                            key={role.id}
                                            className={`role-assign-item ${selectedRoleId === role.id ? 'assigned' : ''}`}
                                        >
                                            <input
                                                type="radio"
                                                name="roleSelection"
                                                checked={selectedRoleId === role.id}
                                                onChange={() => setSelectedRoleId(role.id)}
                                            />
                                            <div className="role-assign-label">
                                                <span className="role-assign-name">
                                                    {role.isSystemRole ? '' : '⚙️'} {role.roleName}
                                                </span>
                                                <span className="role-assign-type">
                                                    {role.isSystemRole ? 'System' : 'Custom'} · {(role.permissions || []).length} permissions
                                                </span>
                                            </div>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Actions */}
                        <div className="user-form-actions">
                            <button
                                type="submit"
                                className="btn btn-primary"
                                disabled={saving}
                            >
                                {saving ? 'Creating...' : '✓ Create User'}
                            </button>
                            <Link href="/users" className="btn btn-secondary">
                                Cancel
                            </Link>
                        </div>
                    </form>
                </div>
            </div>
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../../components/Navbar';
import {
    getUser, updateUser, getRoles,
    assignRoleToUser, removeRoleFromUser
} from '../../../services/api';
import { toastSuccess, toastError } from '../../../services/toast';
import { useAuth } from '../../../context/AuthContext';

export default function EditUserPage() {
    const router = useRouter();
    const { id } = router.query;
    const { user: authUser, loading: authLoading } = useAuth();

    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [originalUser, setOriginalUser] = useState(null);
    const [allRoles, setAllRoles] = useState([]);
    const [userRoleIds, setUserRoleIds] = useState(new Set());
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [roleLoading, setRoleLoading] = useState(null); // roleId being toggled
    const [error, setError] = useState('');

    useEffect(() => {
        if (!id || authLoading) return;
        if (!authUser) { router.replace('/login'); return; }
        Promise.all([loadUser(), loadRoles()])
            .catch(() => {})
            .finally(() => setLoading(false));
    }, [id, authLoading, authUser, router]);

    async function loadUser() {
        try {
            const user = await getUser(id);
            setOriginalUser(user);
            setName(user.name || '');
            setEmail(user.email || '');
            setUserRoleIds(new Set((user.roles || []).map(r => r.id)));
        } catch (err) {
            if (err.status === 403) {
                toastError('You do not have permission to edit users.');
                router.replace('/dashboard');
            } else if (err.status === 404) {
                toastError('User not found.');
                router.replace('/users');
            } else {
                toastError('Failed to load user.');
                router.replace('/users');
            }
        }
    }

    async function loadRoles() {
        try {
            const data = await getRoles();
            setAllRoles(Array.isArray(data) ? data : []);
        } catch {
            // Non-critical — roles section just won't show
        }
    }

    // Profile save (name + email only)
    async function handleSaveProfile(e) {
        e.preventDefault();
        setError('');
        setSaving(true);
        try {
            const updated = await updateUser(id, {
                name: name.trim() || null,
                email: email.trim() || null
            });
            setOriginalUser(updated);
            toastSuccess('User profile updated.');
        } catch (err) {
            const msg = err.message || 'Failed to update user.';
            setError(msg);
            toastError(msg);
        } finally {
            setSaving(false);
        }
    }

    // Toggle role assignment (instant — no form submit needed)
    async function handleToggleRole(roleId) {
        setRoleLoading(roleId);
        try {
            let updated;
            if (userRoleIds.has(roleId)) {
                updated = await removeRoleFromUser(id, roleId);
                toastSuccess('Role removed.');
            } else {
                updated = await assignRoleToUser(id, roleId);
                toastSuccess('Role assigned.');
            }
            // Refresh user state from response
            setOriginalUser(updated);
            setUserRoleIds(new Set((updated.roles || []).map(r => r.id)));
        } catch (err) {
            toastError(err.message || 'Failed to update role.');
        } finally {
            setRoleLoading(null);
        }
    }

    const profileChanged = originalUser && (
        (name.trim() || '') !== (originalUser.name || '') ||
        (email.trim() || '') !== (originalUser.email || '')
    );

    if (loading) {
        return (
            <>
                <Head><title>Edit User — FormCraft</title></Head>
                <Navbar />
                <div className="users-page">
                    <div className="users-skeleton">
                        {[...Array(4)].map((_, i) => (
                            <div key={i} className="users-skeleton-row" />
                        ))}
                    </div>
                </div>
            </>
        );
    }

    if (!originalUser) return null;

    return (
        <>
            <Head>
                <title>Edit {originalUser.name || originalUser.username} — FormCraft</title>
            </Head>
            <Navbar />

            <div className="users-page">
                <div className="users-page-header">
                    <div>
                        <h1>Edit User: {originalUser.name || originalUser.username}</h1>
                        <p>Update profile information and manage role assignments</p>
                    </div>
                    <Link href="/users" className="btn btn-secondary">
                        ← Back to Users
                    </Link>
                </div>

                <div className="user-form-card">
                    {/* Error Banner */}
                    {error && (
                        <div style={{
                            padding: '12px 16px', marginBottom: 20,
                            background: 'rgba(239,68,68,0.1)',
                            border: '1px solid rgba(239,68,68,0.3)',
                            borderRadius: 'var(--radius-sm)',
                            color: '#FCA5A5', fontSize: 14
                        }}>
                            ⚠ {error}
                        </div>
                    )}

                    {/* ── Profile Section ───────────────────── */}
                    <form onSubmit={handleSaveProfile}>
                        <h2>Profile Information</h2>

                        {/* Username (read-only) */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label">Username</label>
                            <input
                                type="text"
                                className="form-input"
                                value={originalUser.username}
                                disabled
                                style={{ opacity: 0.5, cursor: 'not-allowed' }}
                            />
                            <span style={{ fontSize: 11, color: 'var(--text-muted)' }}>
                                Username cannot be changed after creation.
                            </span>
                        </div>

                        {/* Display Name */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="name">
                                Display Name
                            </label>
                            <input
                                id="name"
                                type="text"
                                className="form-input"
                                placeholder="e.g. John Doe"
                                value={name}
                                onChange={e => setName(e.target.value)}
                                maxLength={100}
                            />
                        </div>

                        {/* Email */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="email">
                                Email
                            </label>
                            <input
                                id="email"
                                type="email"
                                className="form-input"
                                placeholder="e.g. john@example.com"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                maxLength={150}
                            />
                        </div>

                        {/* Save Profile */}
                        <div className="user-form-actions" style={{ borderTop: 'none', marginTop: 8, paddingTop: 0 }}>
                            <button
                                type="submit"
                                className="btn btn-primary"
                                disabled={saving || !profileChanged}
                            >
                                {saving ? 'Saving...' : '✓ Save Profile'}
                            </button>
                            {!profileChanged && !saving && (
                                <span style={{ fontSize: 12, color: 'var(--text-muted)', alignSelf: 'center' }}>
                                    No profile changes to save
                                </span>
                            )}
                        </div>
                    </form>

                    {/* ── Role Assignment Section ────────────── */}
                    {allRoles.length > 0 && (
                        <div className="role-assign-section">
                            <h3>Role Assignments</h3>
                            <span style={{ fontSize: 12, color: 'var(--text-muted)', display: 'block', marginBottom: 4 }}>
                                Click to assign or remove roles instantly. Changes are saved automatically.
                            </span>
                            <span style={{ fontSize: 12, color: 'var(--text-muted)', display: 'block', marginBottom: 16 }}>
                                {userRoleIds.size} role{userRoleIds.size !== 1 ? 's' : ''} assigned
                            </span>

                            {/* Current roles as chips */}
                            {userRoleIds.size > 0 && (
                                <div style={{ marginBottom: 16 }}>
                                    <span style={{ fontSize: 11, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 700 }}>
                                        Current Roles
                                    </span>
                                    <div className="current-roles-list">
                                        {(originalUser.roles || []).map(role => (
                                            <span
                                                key={role.id}
                                                className={`current-role-chip ${role.isSystemRole ? 'system-chip' : 'custom-chip'}`}
                                            >
                                                {role.isSystemRole ? '' : '⚙️'} {role.roleName}
                                                <span
                                                    className="chip-remove"
                                                    title={`Remove ${role.roleName}`}
                                                    onClick={() => handleToggleRole(role.id)}
                                                >
                                                    ✕
                                                </span>
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* All roles grid with checkboxes */}
                            <div className="role-assign-grid">
                                {allRoles.map(role => {
                                    const isAssigned = userRoleIds.has(role.id);
                                    const isToggling = roleLoading === role.id;

                                    return (
                                        <label
                                            key={role.id}
                                            className={`role-assign-item ${isAssigned ? 'assigned' : ''}`}
                                            style={isToggling ? { opacity: 0.5, pointerEvents: 'none' } : {}}
                                        >
                                            <input
                                                type="checkbox"
                                                checked={isAssigned}
                                                onChange={() => handleToggleRole(role.id)}
                                                disabled={isToggling}
                                            />
                                            <div className="role-assign-label">
                                                <span className="role-assign-name">
                                                    {role.isSystemRole ? '' : '⚙️'} {role.roleName}
                                                    {isToggling && ' …'}
                                                </span>
                                                <span className="role-assign-type">
                                                    {role.isSystemRole ? 'System' : 'Custom'} · {(role.permissions || []).length} permissions
                                                </span>
                                            </div>
                                        </label>
                                    );
                                })}
                            </div>

                            {/* Effective permissions display */}
                            {originalUser.permissions && originalUser.permissions.length > 0 && (
                                <div style={{ marginTop: 20 }}>
                                    <span style={{
                                        fontSize: 11, color: 'var(--text-muted)',
                                        textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 700,
                                        display: 'block', marginBottom: 8
                                    }}>
                                        Effective Permissions
                                    </span>
                                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 5 }}>
                                        {originalUser.permissions.map(p => (
                                            <span key={p} className="perm-tag">{p}</span>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../../components/Navbar';
import {
    getUser, updateUser, getRoles,
    assignRoleToUser
} from '../../../services/api';
import { toastSuccess, toastError } from '../../../services/toast';
import { useAuth } from '../../../context/AuthContext';

export default function EditUserPage() {
    const router = useRouter();
    const { id } = router.query;
    const { user: authUser, loading: authLoading } = useAuth();

    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [originalUser, setOriginalUser] = useState(null);
    const [allRoles, setAllRoles] = useState([]);
    const [userRoleId, setUserRoleId] = useState(null);
    const [selectedRoleId, setSelectedRoleId] = useState(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [roleLoading, setRoleLoading] = useState(null); // roleId being toggled
    const [error, setError] = useState('');

    useEffect(() => {
        if (!id || authLoading) return;
        if (!authUser) { router.replace('/login'); return; }
        Promise.all([loadUser(), loadRoles()])
            .catch(() => {})
            .finally(() => setLoading(false));
    }, [id, authLoading, authUser, router]);

    async function loadUser() {
        try {
            const user = await getUser(id);
            setOriginalUser(user);
            setName(user.name || '');
            setEmail(user.email || '');
            const currentRoleId = (user.roles && user.roles.length > 0) ? Number(user.roles[0].id) : null;
            setUserRoleId(currentRoleId);
            setSelectedRoleId(currentRoleId);
        } catch (err) {
            if (err.status === 403) {
                toastError('You do not have permission to edit users.');
                router.replace('/dashboard');
            } else if (err.status === 404) {
                toastError('User not found.');
                router.replace('/users');
            } else {
                toastError('Failed to load user.');
                router.replace('/users');
            }
        }
    }

    async function loadRoles() {
        try {
            const data = await getRoles();
            setAllRoles(Array.isArray(data) ? data : []);
        } catch {
            // Non-critical — roles section just won't show
        }
    }

    // Profile save (name + email only)
    async function handleSaveProfile(e) {
        e.preventDefault();
        setError('');
        setSaving(true);
        try {
            const updated = await updateUser(id, {
                name: name.trim() || null,
                email: email.trim() || null
            });
            setOriginalUser(updated);
            toastSuccess('User profile updated.');
        } catch (err) {
            const msg = err.message || 'Failed to update user.';
            setError(msg);
            toastError(msg);
        } finally {
            setSaving(false);
        }
    }

    async function handleApplyRoleChange() {
        if (roleLoading !== null) return;
        const nextRoleId = Number(selectedRoleId);
        if (!nextRoleId || userRoleId === nextRoleId) return;

        setRoleLoading(nextRoleId);
        try {
            const updated = await assignRoleToUser(id, nextRoleId);
            toastSuccess('Role updated.');
            // Refresh user state from response
            setOriginalUser(updated);
            const updatedRoleId = (updated.roles && updated.roles.length > 0) ? Number(updated.roles[0].id) : null;
            setUserRoleId(updatedRoleId);
            setSelectedRoleId(updatedRoleId);
        } catch (err) {
            toastError(err.message || 'Failed to update role.');
        } finally {
            setRoleLoading(null);
        }
    }

    const profileChanged = originalUser && (
        (name.trim() || '') !== (originalUser.name || '') ||
        (email.trim() || '') !== (originalUser.email || '')
    );
    const roleChanged = selectedRoleId !== userRoleId;

    if (loading) {
        return (
            <>
                <Head><title>Edit User — FormCraft</title></Head>
                <Navbar />
                <div className="users-page">
                    <div className="users-skeleton">
                        {[...Array(4)].map((_, i) => (
                            <div key={i} className="users-skeleton-row" />
                        ))}
                    </div>
                </div>
            </>
        );
    }

    if (!originalUser) return null;

    return (
        <>
            <Head>
                <title>Edit {originalUser.name || originalUser.username} — FormCraft</title>
            </Head>
            <Navbar />

            <div className="users-page">
                <div className="users-page-header">
                    <div>
                        <h1>Edit User: {originalUser.name || originalUser.username}</h1>
                        <p>Update profile information and manage role assignments</p>
                    </div>
                    <Link href="/users" className="btn btn-secondary">
                        ← Back to Users
                    </Link>
                </div>

                <div className="user-form-card">
                    {/* Error Banner */}
                    {error && (
                        <div style={{
                            padding: '12px 16px', marginBottom: 20,
                            background: 'rgba(239,68,68,0.1)',
                            border: '1px solid rgba(239,68,68,0.3)',
                            borderRadius: 'var(--radius-sm)',
                            color: '#FCA5A5', fontSize: 14
                        }}>
                            ⚠ {error}
                        </div>
                    )}

                    {/* ── Profile Section ───────────────────── */}
                    <form onSubmit={handleSaveProfile}>
                        <h2>Profile Information</h2>

                        {/* Username (read-only) */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label">Username</label>
                            <input
                                type="text"
                                className="form-input"
                                value={originalUser.username}
                                disabled
                                style={{ opacity: 0.5, cursor: 'not-allowed' }}
                            />
                            <span style={{ fontSize: 11, color: 'var(--text-muted)' }}>
                                Username cannot be changed after creation.
                            </span>
                        </div>

                        {/* Display Name */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="name">
                                Display Name
                            </label>
                            <input
                                id="name"
                                type="text"
                                className="form-input"
                                placeholder="e.g. John Doe"
                                value={name}
                                onChange={e => setName(e.target.value)}
                                maxLength={100}
                            />
                        </div>

                        {/* Email */}
                        <div className="form-group" style={{ marginBottom: 20 }}>
                            <label className="form-label" htmlFor="email">
                                Email
                            </label>
                            <input
                                id="email"
                                type="email"
                                className="form-input"
                                placeholder="e.g. john@example.com"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                maxLength={150}
                            />
                        </div>

                        {/* Save Profile */}
                        <div className="user-form-actions" style={{ borderTop: 'none', marginTop: 8, paddingTop: 0 }}>
                            <button
                                type="submit"
                                className="btn btn-primary"
                                disabled={saving || !profileChanged}
                            >
                                {saving ? 'Saving...' : '✓ Save Profile'}
                            </button>
                            {!profileChanged && !saving && (
                                <span style={{ fontSize: 12, color: 'var(--text-muted)', alignSelf: 'center' }}>
                                    No profile changes to save
                                </span>
                            )}
                        </div>
                    </form>

                    {/* ── Role Assignment Section ────────────── */}
                    {allRoles.length > 0 && (
                        <div className="role-assign-section">
                            <h3>Role Assignment</h3>
                            <span style={{ fontSize: 12, color: 'var(--text-muted)', display: 'block', marginBottom: 4 }}>
                                Select one role and click Apply Changes.
                            </span>
                            <span style={{ fontSize: 12, color: 'var(--text-muted)', display: 'block', marginBottom: 16 }}>
                                {userRoleId ? '1 role assigned' : 'No role assigned'}
                            </span>

                            {/* Current roles as chips */}
                            {userRoleId && (
                                <div style={{ marginBottom: 16 }}>
                                    <span style={{ fontSize: 11, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 700 }}>
                                        Current Role
                                    </span>
                                    <div className="current-roles-list">
                                        {(originalUser.roles || []).slice(0, 1).map(role => (
                                            <span
                                                key={role.id}
                                                className={`current-role-chip ${role.isSystemRole ? 'system-chip' : 'custom-chip'}`}
                                            >
                                                {role.isSystemRole ? '' : '⚙️'} {role.roleName}
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* All roles grid with checkboxes */}
                            <div className="role-assign-grid">
                                {allRoles.map(role => {
                                    const roleId = Number(role.id);
                                    const isAssigned = selectedRoleId === roleId;
                                    const isToggling = roleLoading === roleId;

                                    return (
                                        <label
                                            key={role.id}
                                            className={`role-assign-item ${isAssigned ? 'assigned' : ''}`}
                                            style={isToggling ? { opacity: 0.5, pointerEvents: 'none' } : {}}
                                        >
                                            <input
                                                type="radio"
                                                name="roleSelection"
                                                checked={isAssigned}
                                                onChange={() => setSelectedRoleId(roleId)}
                                                disabled={isToggling}
                                            />
                                            <div className="role-assign-label">
                                                <span className="role-assign-name">
                                                    {role.isSystemRole ? '' : '⚙️'} {role.roleName}
                                                    {isToggling && ' …'}
                                                </span>
                                                <span className="role-assign-type">
                                                    {role.isSystemRole ? 'System' : 'Custom'} · {(role.permissions || []).length} permissions
                                                </span>
                                            </div>
                                        </label>
                                    );
                                })}
                            </div>

                            <div className="user-form-actions" style={{ borderTop: 'none', marginTop: 12, paddingTop: 0 }}>
                                <button
                                    type="button"
                                    className="btn btn-primary"
                                    onClick={handleApplyRoleChange}
                                    disabled={roleLoading !== null || !roleChanged || !selectedRoleId}
                                >
                                    {roleLoading !== null ? 'Applying...' : 'Apply Changes'}
                                </button>
                                {!roleChanged && roleLoading === null && (
                                    <span style={{ fontSize: 12, color: 'var(--text-muted)', alignSelf: 'center' }}>
                                        No role changes to apply
                                    </span>
                                )}
                            </div>

                            {/* Effective permissions display */}
                            {originalUser.permissions && originalUser.permissions.length > 0 && (
                                <div style={{ marginTop: 20 }}>
                                    <span style={{
                                        fontSize: 11, color: 'var(--text-muted)',
                                        textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 700,
                                        display: 'block', marginBottom: 8
                                    }}>
                                        Effective Permissions
                                    </span>
                                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 5 }}>
                                        {originalUser.permissions.map(p => (
                                            <span key={p} className="perm-tag">{p}</span>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Navbar from '../../components/Navbar';
import { getUsers, deleteUser, removeRoleFromUser } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

export default function UsersPage() {
    const router = useRouter();
    const { user, loading: authLoading } = useAuth();
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [deleteTarget, setDeleteTarget] = useState(null);
    const [deleting, setDeleting] = useState(false);
    const [search, setSearch] = useState('');

    useEffect(() => {
        if (authLoading) return;
        if (!user) { router.replace('/login'); return; }
        loadUsers();
    }, [authLoading, user, router]);

    async function loadUsers() {
        try {
            const data = await getUsers();
            setUsers(Array.isArray(data) ? data : []);
        } catch (err) {
            if (err.status === 403) {
                toastError('You do not have permission to manage users.');
                router.replace('/dashboard');
            } else {
                toastError('Failed to load users.');
            }
        } finally {
            setLoading(false);
        }
    }

    const filtered = users.filter(u => {
        const q = search.toLowerCase();
        return (
            (u.name || '').toLowerCase().includes(q) ||
            (u.username || '').toLowerCase().includes(q) ||
            (u.email || '').toLowerCase().includes(q) ||
            (u.roles || []).some(r => r.roleName.toLowerCase().includes(q))
        );
    });

    async function handleDelete() {
        if (!deleteTarget) return;
        setDeleting(true);
        try {
            await deleteUser(deleteTarget.id);
            setUsers(prev => prev.filter(u => u.id !== deleteTarget.id));
            toastSuccess(`User "${deleteTarget.name || deleteTarget.username}" deleted.`);
        } catch (err) {
            toastError(err.message || 'Failed to delete user.');
        } finally {
            setDeleting(false);
            setDeleteTarget(null);
        }
    }

    async function handleRemoveRole(userId, roleId, roleName) {
        try {
            const updated = await removeRoleFromUser(userId, roleId);
            setUsers(prev => prev.map(u => u.id === userId ? updated : u));
            toastSuccess(`Role "${roleName}" removed.`);
        } catch (err) {
            toastError(err.message || 'Failed to remove role.');
        }
    }

    function getInitials(user) {
        if (user.name) {
            return user.name.split(' ').map(w => w[0]).join('').slice(0, 2);
        }
        return user.username ? user.username.slice(0, 2) : '?';
    }

    return (
        <>
            <Head>
                <title>User Management — FormCraft</title>
            </Head>
            <Navbar />

            <div className="users-page">
                <div className="users-page-header">
                    <div>
                        <h1> User Management</h1>
                        <p>Manage users and their role assignments</p>
                    </div>
                    <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                        <input
                            type="text"
                            className="form-input"
                            placeholder="Search users, emails, roles..."
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            style={{ width: 260 }}
                        />
                    </div>
                </div>

                {loading ? (
                    <div className="users-skeleton">
                        {[...Array(5)].map((_, i) => (
                            <div key={i} className="users-skeleton-row" />
                        ))}
                    </div>
                ) : users.length === 0 ? (
                    <div className="users-empty">
                        <div className="users-empty-icon"></div>
                        <h3>No users found</h3>
                        <p>Users will appear here after they register. You can then assign roles to them.</p>
                    </div>
                ) : (
                    <>
                        <div className="users-table-wrap">
                            <table className="users-table">
                                <thead>
                                    <tr>
                                        <th>User</th>
                                        <th>Email</th>
                                        <th>Roles</th>
                                        <th style={{ width: 100 }}>Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filtered.map(user => (
                                        <tr key={user.id}>
                                            <td data-label="User">
                                                <div className="user-name-cell">
                                                    <div className="user-avatar">
                                                        {getInitials(user)}
                                                    </div>
                                                    <div className="user-name-info">
                                                        <span className="user-display-name">
                                                            {user.name || '—'}
                                                        </span>
                                                        <span className="user-username">
                                                            @{user.username}
                                                        </span>
                                                    </div>
                                                </div>
                                            </td>
                                            <td data-label="Email">
                                                <div className="user-email">
                                                    {user.email ? (
                                                        <a href={`mailto:${user.email}`}>{user.email}</a>
                                                    ) : (
                                                        <span style={{ color: 'var(--text-muted)' }}>—</span>
                                                    )}
                                                </div>
                                            </td>
                                            <td data-label="Roles">
                                                <div className="role-tags">
                                                    {(user.roles || []).map(role => (
                                                        <span
                                                            key={role.id}
                                                            className={`role-tag ${role.isSystemRole ? 'system-tag' : 'custom-tag'}`}
                                                        >
                                                            {role.isSystemRole ? '' : '⚙️'} {role.roleName}
                                                            <span
                                                                className="tag-remove"
                                                                title={`Remove ${role.roleName}`}
                                                                onClick={() => handleRemoveRole(user.id, role.id, role.roleName)}
                                                            >
                                                                ✕
                                                            </span>
                                                        </span>
                                                    ))}
                                                    {(!user.roles || user.roles.length === 0) && (
                                                        <span style={{ color: 'var(--text-muted)', fontSize: 12 }}>No roles</span>
                                                    )}
                                                </div>
                                            </td>
                                            <td data-label="Actions">
                                                <div className="user-actions">
                                                    <button
                                                        className="user-action-btn"
                                                        title="Edit user"
                                                        onClick={() => router.push(`/users/edit/${user.id}`)}
                                                    >
                                                        ✏️
                                                    </button>
                                                    <button
                                                        className="user-action-btn danger"
                                                        title="Delete user"
                                                        onClick={() => setDeleteTarget(user)}
                                                    >
                                                        ️
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>

                        {filtered.length === 0 && search && (
                            <div className="users-empty">
                                <p>No users match &quot;{search}&quot;</p>
                            </div>
                        )}

                        <div style={{ marginTop: 16, fontSize: 12, color: 'var(--text-muted)' }}>
                            Showing {filtered.length} of {users.length} users
                        </div>
                    </>
                )}
            </div>

            {/* Delete Confirmation Modal */}
            {deleteTarget && (
                <div className="user-modal-overlay" onClick={() => !deleting && setDeleteTarget(null)}>
                    <div className="user-modal" onClick={e => e.stopPropagation()}>
                        <h3>Delete User</h3>
                        <p>
                            Are you sure you want to delete <strong>&quot;{deleteTarget.name || deleteTarget.username}&quot;</strong>?
                            All role assignments will be removed. This action cannot be undone.
                        </p>
                        <div className="user-modal-actions">
                            <button
                                className="btn btn-secondary"
                                onClick={() => setDeleteTarget(null)}
                                disabled={deleting}
                            >
                                Cancel
                            </button>
                            <button
                                className="btn btn-danger"
                                onClick={handleDelete}
                                disabled={deleting}
                            >
                                {deleting ? 'Deleting...' : 'Delete User'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

